import React, { useState, useCallback } from 'react';
import { Presentation, AppStatus } from './types';
import { processBrainDump } from './geminiService';
import { Button } from './components/Button';
import { SlideCard } from './components/SlideCard';

const App: React.FC = () => {
  const [brainDump, setBrainDump] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [result, setResult] = useState<Presentation | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brainDump.trim()) return;

    setStatus(AppStatus.PROCESSING);
    setError(null);

    try {
      const data = await processBrainDump(brainDump);
      setResult(data);
      setStatus(AppStatus.COMPLETED);
      // Smooth scroll to results
      setTimeout(() => {
        document.getElementById('results')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err: any) {
      setError(err.message || 'Something went wrong. Take a breath, we can try again.');
      setStatus(AppStatus.ERROR);
    }
  };

  const reset = () => {
    setStatus(AppStatus.IDLE);
    setResult(null);
    setBrainDump('');
    setError(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20 selection:bg-indigo-100 selection:text-indigo-700">
      {/* Header */}
      <header className="py-10 px-6 max-w-5xl mx-auto flex justify-between items-center">
        <div className="flex items-center gap-2 group cursor-default">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-2xl group-hover:rotate-6 transition-transform">
            B
          </div>
          <h1 className="text-2xl font-bold font-heading tracking-tight text-slate-800">
            Brain-Dump <span className="text-indigo-600">→</span> Slides
          </h1>
        </div>

        {status === AppStatus.COMPLETED && (
