              <div className="flex flex-wrap justify-center gap-4 pt-4 opacity-50 cursor-not-allowed">
                <Button variant="ghost" disabled>PPTX Export (Soon)</Button>
                <Button variant="ghost" disabled>Google Slides (Soon)</Button>
              </div>
            </div>

            <div className="text-center">
              <Button onClick={reset} variant="ghost" className="mb-20">
                Start a new Brain Dump
              </Button>
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="mt-auto border-t border-slate-200 py-10 text-center">
        <p className="text-slate-400 text-sm">
          Built for brains that work differently. No shame. Just clarity.
        </p>
      </footer>
    </div>
  );
};

export default App;

import pptxgen from "pptxgenjs";
import { Presentation } from "./types";

export const exportToPptx = async (presentation: Presentation) => {
  const pres = new pptxgen();

  // 1. Title Slide
  const titleSlide = pres.addSlide();
  titleSlide.background = { fill: "F8FAFC" };
  titleSlide.addText("Presentation Outline", {
    x: 0,
    y: "35%",
    w: "100%",
    align: "center",
    fontSize: 44,
    color: "4F46E5", // Indigo-600
    bold: true,
    fontFace: "Arial"
  });
  titleSlide.addText(presentation.summary, {
    x: 0,
    y: "55%",
    w: "100%",
    align: "center",
    fontSize: 18,
    color: "64748B", // Slate-500
    italic: true,
    fontFace: "Arial"
  });

  // 2. Content Slides
  presentation.slides.forEach((slide) => {
    const s = pres.addSlide();
    s.background = { fill: "FFFFFF" };

    // Slide Title
    s.addText(slide.title, {
      x: 0.5,
      y: 0.5,
      w: "90%",
      fontSize: 32,
      bold: true,
      color: "1E293B", // Slate-800
      fontFace: "Arial"
    });

    // Bullets
    const bulletPoints = slide.bullets.map(b => ({ text: b, options: { bullet: true, indentLevel: 0 } }));
    s.addText(bulletPoints, {
      x: 0.5,
      y: 1.5,
      w: "90%",
      h: 3,
      fontSize: 18,
      color: "475569", // Slate-600
      fontFace: "Arial"
    });

    // Visual Cue (Small text at bottom)
    s.addText(`Visual: ${slide.visualContent}`, {
      x: 0.5,
      y: 5.0,
      w: "90%",
      fontSize: 12,
      color: "10B981", // Emerald-500
      italic: true,
      fontFace: "Arial"
    });

    // Speaker Notes
    s.addNotes(slide.speakerNotes);
  });

  // Save File
  await pres.writeFile({ fileName: `Brain-Dump-Presentation.pptx` });
};

import React, { useState } from 'react';
