    if (!result) return;
    setIsExporting(true);
    try {
      await exportToPptx(result);
    } catch (err) {
      console.error("Export failed", err);
      alert("Export failed. You can still copy-paste manually!");
    } finally {
      setIsExporting(false);
    }
  };

  const handleCopyForGoogleSlides = () => {
    if (!result) return;
    const text = result.slides.map((s, i) => 
      `SLIDE ${i+1}: ${s.title}\n` +
      `POINTS:\n${s.bullets.map(b => `- ${b}`).join('\n')}\n` +
      `NOTES: ${s.speakerNotes}\n` +
      `VISUAL: ${s.visualContent}\n` +
      `-------------------`
    ).join('\n\n');

    navigator.clipboard.writeText(text).then(() => {
      alert("Presentation text copied! You can now paste this into Google Slides or use 'Import from File' with the PPTX download.");
    });
  };

  const reset = () => {
    setStatus(AppStatus.IDLE);
    setResult(null);
    setBrainDump('');
    setError(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20 selection:bg-indigo-100 selection:text-indigo-700">
      {/* Header */}
      <header className="py-10 px-6 max-w-5xl mx-auto flex justify-between items-center">
        <div className="flex items-center gap-2 group cursor-default">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-2xl group-hover:rotate-6 transition-transform">
            B
          </div>
          <h1 className="text-2xl font-bold font-heading tracking-tight text-slate-800">
            Brain-Dump <span className="text-indigo-600">→</span> Slides
          </h1>
        </div>

        {status === AppStatus.COMPLETED && (
          <Button variant="ghost" onClick={reset}>
            Start Over
          </Button>
        )}
      </header>

      <main className="max-w-4xl mx-auto px-6">
        {/* Input Section */}
        {status !== AppStatus.COMPLETED && (
