import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { Button } from './Button';

interface VoiceRecorderProps {
  onTranscriptUpdate: (text: string) => void;
  onFinished: () => void;
}

export const VoiceRecorder: React.FC<VoiceRecorderProps> = ({ onTranscriptUpdate, onFinished }) => {
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const fullTranscriptRef = useRef('');

  // Decoding/Encoding helpers (as per SDK rules)
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const startSession = async () => {
    setError(null);
    setIsActive(true);
    fullTranscriptRef.current = '';

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = inputCtx;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then((session) => {
                if (isActive) {
                  session.sendRealtimeInput({ media: pcmBlob });
                }
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              fullTranscriptRef.current += text;
              onTranscriptUpdate(fullTranscriptRef.current);
            }
          },
          onerror: (e) => {
            console.error('Live API Error:', e);
            setError('Connection error. Please try again.');
            stopSession();
          },
          onclose: () => setIsActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: 'You are a supportive listener. Transcribe the user thoughts exactly as they speak. Do not respond verbally unless necessary, just transcribe.'
        },
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      setError(err.message || 'Could not start microphone.');
      setIsActive(false);
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      // In some versions session.close() is used
      try { sessionRef.current.close(); } catch(e) {}
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
    }
    setIsActive(false);
    onFinished();
  };

  return (
    <div className="flex flex-col items-center gap-4 p-6 bg-indigo-50 rounded-3xl border border-indigo-100 animate-in fade-in zoom-in duration-300">
      {!isActive ? (
        <div className="text-center space-y-4">
          <div className="w-16 h-16 bg-indigo-600 rounded-full flex items-center justify-center text-white mx-auto shadow-lg shadow-indigo-200">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </div>
          <h4 className="font-bold text-slate-800">Ready to speak your mind?</h4>
          <p className="text-sm text-slate-500">Just talk, we'll type. Perfect for "venting" your thoughts.</p>
          <Button onClick={startSession} variant="primary">Start Listening</Button>
          {error && <p className="text-xs text-rose-500 font-medium">{error}</p>}
        </div>
      ) : (
        <div className="text-center space-y-6 w-full">
          <div className="relative flex items-center justify-center">
             <div className="absolute w-24 h-24 bg-indigo-500 rounded-full animate-ping opacity-20"></div>
             <div className="relative w-16 h-16 bg-indigo-600 rounded-full flex items-center justify-center text-white z-10">
                <div className="flex gap-1">
                   <div className="w-1 h-4 bg-white rounded-full animate-pulse"></div>
                   <div className="w-1 h-8 bg-white rounded-full animate-pulse delay-75"></div>
                   <div className="w-1 h-6 bg-white rounded-full animate-pulse delay-150"></div>
                </div>
             </div>
          </div>
          <div className="space-y-2">
            <h4 className="font-bold text-indigo-600 animate-pulse">Listening...</h4>
            <div className="max-h-32 overflow-y-auto text-slate-600 text-sm italic px-4">
              {fullTranscriptRef.current || "Wait, keep talking, I'm getting it..."}
            </div>
          </div>
          <Button onClick={stopSession} variant="ghost" className="border-indigo-200 text-indigo-600">
            Stop & Finish Dump
          </Button>
        </div>
      )}
    </div>
  );
};

