export interface Slide {
  title: string;
  bullets: string[];
  visualContent: string;
  spokenContent: string;
  speakerNotes: string;
  recommendedAsVisualOnly: boolean;
  imageUrl?: string; // Base64 or URL of the generated image
}

export interface Presentation {
  summary: string;
  originalThoughtCount: number;
  slideCount: number;
  slides: Slide[];
}

export enum AppStatus {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  GENERATING_IMAGES = 'GENERATING_IMAGES',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { Presentation } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const presentationSchema = {
  type: Type.OBJECT,
  properties: {
    summary: {
      type: Type.STRING,
      description: "A reassuring summary line like: 'You gave me X messy thoughts. I turned them into Y clear slides.'"
    },
    originalThoughtCount: {
      type: Type.INTEGER,
      description: "Approximate count of distinct points found in the input."
    },
    slideCount: {
      type: Type.INTEGER,
      description: "Total number of slides generated."
    },
    slides: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bullets: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "1-4 concise bullet points."
          },
          visualContent: {
            type: Type.STRING,
            description: "Suggestions for charts, images, diagrams, or icons."
          },
          spokenContent: {
            type: Type.STRING,
            description: "A summary of what the presenter should convey."
          },
          speakerNotes: {
            type: Type.STRING,
            description: "Natural, human-sounding talk track. No corporate jargon."
          },
          recommendedAsVisualOnly: {
            type: Type.BOOLEAN,
            description: "True if this slide works better as a pure visual (e.g., a powerful image or large stat)."
          }
        },
        required: ["title", "bullets", "visualContent", "spokenContent", "speakerNotes", "recommendedAsVisualOnly"]
      }
    }
  },
  required: ["summary", "originalThoughtCount", "slideCount", "slides"]
};

export async function processBrainDump(text: string): Promise<Presentation> {
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are a supportive, high-energy presentation coach who helps people with ADHD organize their thoughts.
    Your job is to take a "brain dump" (which may be messy, rambling, nonlinear, or repetitive) and turn it into a clean, logical presentation outline.

    RULES:
    1. Cluster Ideas: Group related thoughts into logical themes.
    2. Deduplicate: Remove repeated concepts or redundant wording. Keep the strongest version.
    3. Logical Flow: Create a sequence that tells a clear story.
    4. Minimalist Bullets: Use 1-4 short, punchy bullets per slide. No walls of text.
    5. Natural Voice: Speaker notes should sound like a human talking to friends/colleagues, not reading a script.
    6. Reassuring Tone: In the summary, remind them they are doing a great job.
    7. Length: Aim for 6-10 slides unless the input is very sparse or very dense.

    Output must be strictly JSON following the provided schema.
  `;

  try {
    const result = await ai.models.generateContent({
      model,
      contents: `Here is my brain dump: \n\n ${text}`,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: presentationSchema,
        temperature: 0.7,
      },
    });

    const jsonStr = result.text.trim();
    return JSON.parse(jsonStr) as Presentation;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to process your brain dump. Let's try again in a moment.");
  }
}

export async function generateSlideImage(slideTitle: string, visualDescription: string): Promise<string> {
  try {
    const prompt = `Create a high-quality, professional presentation slide background or illustrative image for a slide titled "${slideTitle}". The visual style should be clean, modern, and corporate-friendly but creative. Use this description as a guide: ${visualDescription}. Do not include any text or UI elements in the image.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("No image data returned from model");
  } catch (error) {
    console.error("Image Generation Error:", error);
    return ""; // Return empty string to allow slide text to show even if image fails
  }
}

import React, { useState } from 'react';
import { Presentation, AppStatus, Slide } from './types';
import { processBrainDump, generateSlideImage } from './geminiService';
import { exportToPptx } from './exportService';
import { Button } from './components/Button';
import { SlideCard } from './components/SlideCard';
import { VoiceRecorder } from './components/VoiceRecorder';

const App: React.FC = () => {
  const [brainDump, setBrainDump] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [result, setResult] = useState<Presentation | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [showVoiceRecorder, setShowVoiceRecorder] = useState(false);
  const [imageProgress, setImageProgress] = useState({ current: 0, total: 0 });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brainDump.trim()) return;

    setStatus(AppStatus.PROCESSING);
    setError(null);

    try {
      // Step 1: Process text and structure
      const presentationData = await processBrainDump(brainDump);
      setResult(presentationData);

      // Step 2: Generate images for each slide
      setStatus(AppStatus.GENERATING_IMAGES);
      setImageProgress({ current: 0, total: presentationData.slides.length });

      const slidesWithImages: Slide[] = [];

      for (let i = 0; i < presentationData.slides.length; i++) {
        const slide = presentationData.slides[i];
        setImageProgress(prev => ({ ...prev, current: i + 1 }));

        const imageUrl = await generateSlideImage(slide.title, slide.visualContent);
        slidesWithImages.push({ ...slide, imageUrl });
      }

      setResult({ ...presentationData, slides: slidesWithImages });
      setStatus(AppStatus.COMPLETED);

      // Smooth scroll to results
      setTimeout(() => {
        document.getElementById('results')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
