import React, { useState, useRef } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { Button } from './Button';

interface VoiceRecorderProps {
  onTranscriptUpdate: (text: string) => void;
  onFinished: () => void;
}

export const VoiceRecorder: React.FC<VoiceRecorderProps> = ({ onTranscriptUpdate, onFinished }) => {
  const [isConnecting, setIsConnecting] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [interimText, setInterimText] = useState('');

  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const transcriptHistoryRef = useRef<string[]>([]);
  const currentTurnTranscriptRef = useRef('');

  // Manual implementation of encode/decode as per SDK rules
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startSession = async () => {
    setError(null);
    setIsConnecting(true);
    setInterimText('');
    transcriptHistoryRef.current = [];
    currentTurnTranscriptRef.current = '';

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = inputCtx;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsConnecting(false);
            setIsActive(true);

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);

              // CRITICAL: Solely rely on sessionPromise resolves, do not add other condition checks.
              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle User Input Transcription
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              currentTurnTranscriptRef.current += text;
              setInterimText(currentTurnTranscriptRef.current);

              const fullText = [...transcriptHistoryRef.current, currentTurnTranscriptRef.current].join(' ');
              onTranscriptUpdate(fullText);
            }

            // Handle turn completion to commit the current segment
            if (message.serverContent?.turnComplete) {
              if (currentTurnTranscriptRef.current.trim()) {
                transcriptHistoryRef.current.push(currentTurnTranscriptRef.current.trim());
              }
              currentTurnTranscriptRef.current = '';
              setInterimText('');
            }

            // NOTE: Even though we don't play audio, we acknowledge its presence 
            // to ensure the session context remains synchronized.
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio) {
               // Logic for audio output handling could go here if playback was desired
            }
          },
          onerror: (e) => {
            console.error('Live API Error:', e);
            setError('Connection error. Check your microphone or API key.');
            stopSession();
          },
          onclose: () => {
            setIsActive(false);
            setIsConnecting(false);
          },
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: 'You are a quiet, attentive listener for a person with ADHD. Your ONLY job is to transcribe their thoughts accurately as they spill them out. Do not speak unless they ask a direct question. Focus on transcribing every word of their brain dump.'
        },
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      setError(err.message || 'Microphone access denied or connection failed.');
      setIsConnecting(false);
      setIsActive(false);
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
    }
    setIsActive(false);
    setIsConnecting(false);
    onFinished();
  };

  return (
    <div className="flex flex-col items-center gap-4 p-8 bg-white rounded-[2.5rem] border border-indigo-100 shadow-xl shadow-indigo-100/50 animate-in fade-in zoom-in duration-300">
      {!isActive && !isConnecting ? (
        <div className="text-center space-y-6">
          <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white mx-auto shadow-xl shadow-indigo-200 rotate-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </div>
          <div className="space-y-2">
            <h4 className="text-xl font-bold text-slate-800 font-heading">Voice Brain-Dump</h4>
            <p className="text-slate-500 max-w-xs mx-auto leading-relaxed">
              Don't worry about order or grammar. Just talk, and we'll capture everything.
            </p>
          </div>
          <Button onClick={startSession} variant="primary" className="w-full">
            Start Recording
          </Button>
          {error && (
            <div className="flex items-center justify-center gap-2 text-rose-500 text-sm font-medium bg-rose-50 py-2 px-4 rounded-xl border border-rose-100">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
              {error}
            </div>
          )}
        </div>
      ) : (
        <div className="text-center space-y-8 w-full py-4">
          <div className="relative flex items-center justify-center">
             {/* Dynamic voice ripples */}
             <div className="absolute w-32 h-32 bg-indigo-400 rounded-full animate-ping opacity-10"></div>
             <div className="absolute w-24 h-24 bg-indigo-500 rounded-full animate-ping opacity-20 delay-75"></div>
             <div className="relative w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-white z-10 shadow-2xl shadow-indigo-300">
                <div className="flex gap-1.5 items-end h-8">
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1s_infinite] h-4"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1.2s_infinite] h-8"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_0.8s_infinite] h-6"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1.4s_infinite] h-5"></div>
                </div>
             </div>
          </div>

          <div className="space-y-4">
            <h4 className="text-lg font-bold text-indigo-600">
              {isConnecting ? 'Connecting...' : 'I\'m listening...'}
            </h4>
            <div className="min-h-[100px] max-h-40 overflow-y-auto bg-slate-50/50 rounded-2xl p-6 border border-slate-100 text-slate-700 leading-relaxed text-lg">
              {interimText || (isConnecting ? "" : "Go ahead, start speaking your thoughts...")}
              <span className="inline-block w-1.5 h-5 ml-1 bg-indigo-400 animate-pulse rounded-full align-middle"></span>
            </div>
          </div>

          <div className="flex flex-col gap-3">
            <Button onClick={stopSession} variant="primary" className="bg-slate-800 hover:bg-slate-900 shadow-slate-200">
              Stop & Process Slides
            </Button>
            <p className="text-xs text-slate-400 uppercase tracking-widest font-bold">
              Press stop when you're finished venting
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

import pptxgen from "pptxgenjs";
