/**
 * Standard 16:9 slide dimensions in inches for pptxgenjs
 * Width: 10, Height: 5.625
 */
const SLIDE_W = 10;
const SLIDE_H = 5.625;

export const exportToPptx = async (presentation: Presentation) => {
  const pres = new pptxgen();

  // Set layout to 16x9
  pres.layout = 'LAYOUT_16x9';

  // 1. Title Slide
  const titleSlide = pres.addSlide();
  titleSlide.background = { fill: "F8FAFC" };

  titleSlide.addText("Brain-Dump Presentation", {
    x: 1,
    y: 2,
    w: 8,
    align: "center",
    fontSize: 44,
    color: "4F46E5", // Indigo-600
    bold: true,
    fontFace: "Arial"
  });

  titleSlide.addText(presentation.summary, {
    x: 1,
    y: 3.2,
    w: 8,
    align: "center",
    fontSize: 18,
    color: "64748B", // Slate-500
    italic: true,
    fontFace: "Arial"
  });

  // 2. Content Slides
  presentation.slides.forEach((slide) => {
    const s = pres.addSlide();
    s.background = { fill: "FFFFFF" };

    if (slide.imageUrl) {
      if (slide.recommendedAsVisualOnly) {
        // FULL BACKGROUND - Visual Hero Slide
        // Use 'cover' to ensure no stretching regardless of minor aspect ratio differences
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0, 
          y: 0, 
          w: SLIDE_W, 
          h: SLIDE_H,
          sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
        });

        // Add a dark overlay gradient/rectangle at the bottom for text legibility
        s.addShape(pres.ShapeType.rect, {
          x: 0, y: 4.2, w: SLIDE_W, h: 1.5,
          fill: { color: "000000", transparency: 40 }
        });

        s.addText(slide.title, {
          x: 0.5, y: 4.5, w: 9, h: 0.8,
          align: "left",
          fontSize: 32, bold: true, color: "FFFFFF", fontFace: "Arial"
        });
      } else {
        // SIDEBAR LAYOUT - Professional Content Slide
        // Left side image (approx 40% of slide)
        const imgW = 4;
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0, 
          y: 0, 
          w: imgW, 
          h: SLIDE_H,
          sizing: { type: 'cover', w: imgW, h: SLIDE_H }
        });

        // Right side content
        const contentX = 4.4;
        const contentW = 5.1;

        s.addText(slide.title, {
          x: contentX, y: 0.6, w: contentW, 
          fontSize: 28, bold: true, color: "1E293B", fontFace: "Arial"
        });

        const bulletPoints = slide.bullets.map(b => ({ 
          text: b, 
          options: { bullet: true, indentLevel: 0, color: "475569", fontSize: 16 } 
        }));

        s.addText(bulletPoints, {
          x: contentX, y: 1.6, w: contentW, h: 3, 
          fontSize: 16, fontFace: "Arial", align: "left", valign: "top"
        });

        // Small source/visual cue footer
        s.addText(`Visual style: ${slide.visualContent}`, {
          x: contentX, y: 4.8, w: contentW, 
          fontSize: 9, color: "94A3B8", italic: true, fontFace: "Arial"
        });
      }
    } else {
      // TEXT-ONLY FALLBACK
      s.addText(slide.title, {
        x: 1, y: 0.8, w: 8, fontSize: 36, bold: true, color: "1E293B", fontFace: "Arial"
      });

      const bulletPoints = slide.bullets.map(b => ({ 
        text: b, 
        options: { bullet: true, indentLevel: 0, color: "475569", fontSize: 20 } 
      }));

      s.addText(bulletPoints, {
        x: 1, y: 2, w: 8, h: 3, fontSize: 20, fontFace: "Arial"
      });
    }

    // Add Speaker Notes to the slide metadata
    s.addNotes(slide.speakerNotes);
  });

  // Save File
  await pres.writeFile({ fileName: `Brain-Dump-Presentation.pptx` });
};

