                <Button onClick={() => handlePptxExport(result)} isLoading={isExporting}>
                  Download .PPTX
                </Button>
                <Button onClick={() => handleCopyText(result)} variant="ghost">
                  Copy All Text
                </Button>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="mt-auto border-t border-slate-200 py-10 text-center">
        <p className="text-slate-400 text-sm">Built for brains that work differently. No shame. Just clarity.</p>
      </footer>
    </div>
  );
};

