            {/* Final Actions */}
            <div className="bg-white rounded-3xl p-10 border-2 border-indigo-100 text-center space-y-4 shadow-sm">
              <h4 className="text-xl font-bold text-slate-800">Ready to present?</h4>
              <div className="flex flex-wrap justify-center gap-4 pt-4">
                <Button onClick={() => handlePptxExport(result)} isLoading={isExporting}>
                  Download .PPTX
                </Button>
                <Button onClick={() => handleCopyText(result)} variant="ghost">
                  Copy All Text
                </Button>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="mt-auto border-t border-slate-200 py-10 text-center">
        <p className="text-slate-400 text-sm">Built for brains that work differently. No shame. Just clarity.</p>
      </footer>
    </div>
  );
};

