import pptxgen from "pptxgenjs";
import { Presentation } from "./types";

/**
 * Standard 16:9 slide dimensions in inches for pptxgenjs
 * Width: 10, Height: 5.625
 */
const SLIDE_W = 10;
const SLIDE_H = 5.625;

export const exportToPptx = async (presentation: Presentation) => {
  const pres = new pptxgen();

  // Set layout to 16x9
  pres.layout = 'LAYOUT_16x9';

  // 1. Title Slide
  const titleSlide = pres.addSlide();
  titleSlide.background = { fill: "F8FAFC" };

  // Decorative element
  titleSlide.addShape(pres.ShapeType.rect, {
    x: 0, y: 0, w: 0.5, h: SLIDE_H, fill: { color: "4F46E5" }
  });

  titleSlide.addText("Brain-Dump Presentation", {
    x: 1,
    y: 1.8,
    w: 8,
    align: "left",
    fontSize: 48,
    color: "1E293B",
    bold: true,
    fontFace: "Arial"
  });

  titleSlide.addText(presentation.summary, {
    x: 1,
    y: 3.0,
    w: 7,
    align: "left",
    fontSize: 20,
    color: "64748B",
    italic: true,
    fontFace: "Arial"
  });

  // 2. Content Slides
  presentation.slides.forEach((slide) => {
    const s = pres.addSlide();
    s.background = { fill: "FFFFFF" };

    if (slide.imageUrl) {
      if (slide.recommendedAsVisualOnly) {
        // FULL BACKGROUND - Visual Hero Slide
        // Since both slide and image are 16:9, 'cover' fills perfectly without distortion
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0, 
          y: 0, 
          w: SLIDE_W, 
          h: SLIDE_H,
          sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
        });

        // Add a professional semi-transparent gradient-like bar at the bottom
        s.addShape(pres.ShapeType.rect, {
          x: 0, y: 4.4, w: SLIDE_W, h: 1.225,
          fill: { color: "000000", transparency: 50 }
        });

        s.addText(slide.title, {
          x: 0.5, y: 4.6, w: 9, h: 0.8,
          align: "left",
          fontSize: 36, bold: true, color: "FFFFFF", fontFace: "Arial"
        });
      } else {
        // PROFESSIONAL SIDE-BY-SIDE LAYOUT
        // To keep 16:9 aspect ratio (1.77) without cropping:
        // If we want the image to occupy roughly half the slide width (5 inches):
        // Height = 5 / 1.77 = 2.81 inches.

        const imgW = 5.0;
        const imgH = 2.81; // Perfectly 16:9 for a 5-inch width
        const imgY = (SLIDE_H - imgH) / 2; // Center vertically

        // Light background for the image area to give it a "frame" feel
        s.addShape(pres.ShapeType.rect, {
          x: 0, y: 0, w: 5.5, h: SLIDE_H,
          fill: { color: "F1F5F9" }
        });

        s.addImage({ 
          data: slide.imageUrl, 
          x: 0.25, 
          y: imgY, 
          w: imgW, 
          h: imgH,
          sizing: { type: 'contain', w: imgW, h: imgH }
        });

        // Right side content
        const contentX = 5.8;
        const contentW = 3.8;

        s.addText(slide.title, {
          x: contentX, y: 0.8, w: contentW, 
          fontSize: 32, bold: true, color: "1E293B", fontFace: "Arial",
          margin: 0
        });

        // Ensure bullet points are individual objects for clean rendering
        const bulletObjects = slide.bullets.map(b => ({ 
          text: b, 
          options: { 
            bullet: { code: '2022' }, 
            indentLevel: 0, 
            color: "475569", 
            fontSize: 18,
            lineSpacing: 28 // Professional breathing room
          } 
        }));

        s.addText(bulletObjects, {
          x: contentX, y: 1.8, w: contentW, h: 3, 
          fontSize: 18, fontFace: "Arial", align: "left", valign: "top"
        });

        // Small style caption
        s.addText(`Visual style: ${slide.visualContent}`, {
          x: 5.8, y: 5.0, w: 4, 
          fontSize: 8, color: "94A3B8", italic: true, fontFace: "Arial"
        });
      }
    } else {
      // TEXT-ONLY FALLBACK - Centered Layout
      s.addText(slide.title, {
        x: 1, y: 1.0, w: 8, fontSize: 42, bold: true, color: "1E293B", fontFace: "Arial", align: "center"
      });

      const bulletPoints = slide.bullets.map(b => ({ 
        text: b, 
        options: { bullet: true, color: "475569", fontSize: 24, lineSpacing: 36 } 
      }));

      s.addText(bulletPoints, {
        x: 1.5, y: 2.2, w: 7, h: 3, fontSize: 24, fontFace: "Arial", align: "left"
      });
    }

    // Add Speaker Notes to the slide metadata
    s.addNotes(slide.speakerNotes);
  });

  // Save File
  await pres.writeFile({ fileName: `Brain-Dump-${new Date().getTime()}.pptx` });
};

