               <div className="relative z-10 space-y-6">
                 <h2 className="text-4xl md:text-5xl font-bold font-heading">You're not behind.</h2>
                 <p className="text-xl text-indigo-100 italic font-medium">"{result.summary}"</p>
               </div>
            </div>

            {/* Slides List */}
            <div className="space-y-8">
              <h3 className="text-2xl font-bold text-slate-800 font-heading">The Slide Outline</h3>
              <div className="space-y-8">
                {result.slides.map((slide, index) => (
                  <SlideCard key={index} slide={slide} index={index} />
