import { GoogleGenAI, Type } from "@google/genai";
import { Presentation } from "./types";

const presentationSchema = {
  type: Type.OBJECT,
  properties: {
    summary: {
      type: Type.STRING,
      description: "A reassuring summary line like: 'You gave me X messy thoughts. I turned them into Y clear slides.'"
    },
    originalThoughtCount: {
      type: Type.INTEGER,
      description: "Approximate count of distinct points found in the input."
    },
    slideCount: {
      type: Type.INTEGER,
      description: "Total number of slides generated."
    },
    slides: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bullets: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "1-4 concise bullet points."
          },
          visualContent: {
            type: Type.STRING,
            description: "Suggestions for charts, images, diagrams, or icons."
          },
          spokenContent: {
            type: Type.STRING,
            description: "A summary of what the presenter should convey."
          },
          speakerNotes: {
            type: Type.STRING,
            description: "Natural, human-sounding talk track. No corporate jargon."
          },
          recommendedAsVisualOnly: {
            type: Type.BOOLEAN,
            description: "True if this slide works better as a pure visual (e.g., a powerful image or large stat)."
          }
        },
        required: ["title", "bullets", "visualContent", "spokenContent", "speakerNotes", "recommendedAsVisualOnly"]
      }
    }
  },
  required: ["summary", "originalThoughtCount", "slideCount", "slides"]
};

export async function processBrainDump(text: string): Promise<Presentation> {
  // Initialize AI client inside the function to ensure the correct environment key is used.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are a supportive, high-energy presentation coach who helps people with ADHD organize their thoughts.
    Your job is to take a "brain dump" (which may be messy, rambling, nonlinear, or repetitive) and turn it into a clean, logical presentation outline.

    RULES:
    1. Cluster Ideas: Group related thoughts into logical themes.
    2. Deduplicate: Remove repeated concepts or redundant wording. Keep the strongest version.
    3. Logical Flow: Create a sequence that tells a clear story.
    4. Minimalist Bullets: Use 1-4 short, punchy bullets per slide. No walls of text.
    5. Natural Voice: Speaker notes should sound like a human talking to friends/colleagues, not reading a script.
    6. Reassuring Tone: In the summary, remind them they are doing a great job.
    7. Length: Aim for 6-10 slides unless the input is very sparse or very dense.

    Output must be strictly JSON following the provided schema.
  `;

  try {
    const result = await ai.models.generateContent({
      model,
      contents: `Here is my brain dump: \n\n ${text}`,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: presentationSchema,
        temperature: 0.7,
      },
    });

    const jsonStr = result.text.trim();
    const data = JSON.parse(jsonStr);

    return {
      ...data,
      id: crypto.randomUUID(),
      timestamp: Date.now()
    } as Presentation;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to process your brain dump. Let's try again in a moment.");
  }
}

export async function generateSlideImage(slideTitle: string, visualDescription: string): Promise<string> {
  // Initialize AI client inside the function to ensure the correct environment key is used.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const prompt = `Create a high-quality, professional presentation slide background or illustrative image for a slide titled "${slideTitle}". The visual style should be clean, modern, and corporate-friendly but creative. Use this description as a guide: ${visualDescription}. Do not include any text or UI elements in the image.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("No image data returned from model");
  } catch (error) {
    console.error("Image Generation Error:", error);
    return ""; // Return empty string to allow slide text to show even if image fails
  }
}

import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import React, { useRef, useState } from 'react';
import { Button } from './Button';

interface VoiceRecorderProps {
  onTranscriptUpdate: (text: string) => void;
  onFinished: () => void;
}

export const VoiceRecorder: React.FC<VoiceRecorderProps> = ({ onTranscriptUpdate, onFinished }) => {
  const [isConnecting, setIsConnecting] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [interimText, setInterimText] = useState('');

  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const transcriptHistoryRef = useRef<string[]>([]);
  const currentTurnTranscriptRef = useRef('');

  // Manual implementation of encode/decode as per SDK rules
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startSession = async () => {
    setError(null);
    setIsConnecting(true);
    setInterimText('');
    transcriptHistoryRef.current = [];
    currentTurnTranscriptRef.current = '';

    try {
      // Initialize AI client right before the connection to use the latest API key.
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = inputCtx;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsConnecting(false);
            setIsActive(true);

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);

              // CRITICAL: Solely rely on sessionPromise resolves, do not add other condition checks.
              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle User Input Transcription
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              currentTurnTranscriptRef.current += text;
              setInterimText(currentTurnTranscriptRef.current);

              const fullText = [...transcriptHistoryRef.current, currentTurnTranscriptRef.current].join(' ');
              onTranscriptUpdate(fullText);
            }

            // Handle turn completion to commit the current segment
            if (message.serverContent?.turnComplete) {
              if (currentTurnTranscriptRef.current.trim()) {
                transcriptHistoryRef.current.push(currentTurnTranscriptRef.current.trim());
              }
              currentTurnTranscriptRef.current = '';
              setInterimText('');
            }

            // NOTE: Even though we don't play audio, we acknowledge its presence 
            // to ensure the session context remains synchronized.
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio) {
               // Logic for audio output handling could go here if playback was desired
            }
          },
          onerror: (e) => {
            console.error('Live API Error:', e);
            setError('Connection error. Check your microphone or API key.');
            stopSession();
          },
          onclose: () => {
            setIsActive(false);
            setIsConnecting(false);
          },
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: 'You are a quiet, attentive listener for a person with ADHD. Your ONLY job is to transcribe their thoughts accurately as they spill them out. Do not speak unless they ask a direct question. Focus on transcribing every word of their brain dump.'
        },
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      setError(err.message || 'Microphone access denied or connection failed.');
      setIsConnecting(false);
      setIsActive(false);
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
    }
    setIsActive(false);
    setIsConnecting(false);
    onFinished();
  };

  return (
    <div className="flex flex-col items-center gap-4 p-8 bg-white rounded-[2.5rem] border border-indigo-100 shadow-xl shadow-indigo-100/50 animate-in fade-in zoom-in duration-300">
      {!isActive && !isConnecting ? (
        <div className="text-center space-y-6">
          <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white mx-auto shadow-xl shadow-indigo-200 rotate-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </div>
          <div className="space-y-2">
            <h4 className="text-xl font-bold text-slate-800 font-heading">Voice Brain-Dump</h4>
            <p className="text-slate-500 max-w-xs mx-auto leading-relaxed">
              Don't worry about order or grammar. Just talk, and we'll capture everything.
            </p>
          </div>
          <Button onClick={startSession} variant="primary" className="w-full">
            Start Recording
          </Button>
          {error && (
            <div className="flex items-center justify-center gap-2 text-rose-500 text-sm font-medium bg-rose-50 py-2 px-4 rounded-xl border border-rose-100">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
              {error}
            </div>
          )}
        </div>
      ) : (
        <div className="text-center space-y-8 w-full py-4">
          <div className="relative flex items-center justify-center">
             {/* Dynamic voice ripples */}
             <div className="absolute w-32 h-32 bg-indigo-400 rounded-full animate-ping opacity-10"></div>
             <div className="absolute w-24 h-24 bg-indigo-500 rounded-full animate-ping opacity-20 delay-75"></div>
             <div className="relative w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-white z-10 shadow-2xl shadow-indigo-300">
                <div className="flex gap-1.5 items-end h-8">
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1s_infinite] h-4"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1.2s_infinite] h-8"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_0.8s_infinite] h-6"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1.4s_infinite] h-5"></div>
                </div>
             </div>
          </div>

          <div className="space-y-4">
            <h4 className="text-lg font-bold text-indigo-600">
              {isConnecting ? 'Connecting...' : 'I\'m listening...'}
            </h4>
            <div className="min-h-[100px] max-h-40 overflow-y-auto bg-slate-50/50 rounded-2xl p-6 border border-slate-100 text-slate-700 leading-relaxed text-lg">
              {interimText || (isConnecting ? "" : "Go ahead, start speaking your thoughts...")}
              <span className="inline-block w-1.5 h-5 ml-1 bg-indigo-400 animate-pulse rounded-full align-middle"></span>
            </div>
          </div>

          <div className="flex flex-col gap-3">
            <Button onClick={stopSession} variant="primary" className="bg-slate-800 hover:bg-slate-900 shadow-slate-200">
              Stop & Process Slides
            </Button>
            <p className="text-xs text-slate-400 uppercase tracking-widest font-bold">
              Press stop when you're finished venting
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { processBrainDump, generateSlideImage } from './geminiService';
import { exportToPptx } from './exportService';
import { Button } from './components/Button';
import { SlideCard } from './components/SlideCard';
import { VoiceRecorder } from './components/VoiceRecorder';
import { HistoryView } from './components/HistoryView';
import { Presentation, AppStatus, Slide } from './types';

const STORAGE_KEY = 'brain_dump_history_v1';
const MIN_HISTORY_COUNT = 5;

const App: React.FC = () => {
  const [brainDump, setBrainDump] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [result, setResult] = useState<Presentation | null>(null);
  const [history, setHistory] = useState<Presentation[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [showVoiceRecorder, setShowVoiceRecorder] = useState(false);
  const [imageProgress, setImageProgress] = useState({ current: 0, total: 0 });

  // Load history from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  /**
   * Saves history to localStorage. 
   * If storage limit is hit, it iteratively prunes oldest items 
   * until it fits, prioritizing the last 5 items as requested.
   */
  const saveHistory = (newHistory: Presentation[]) => {
    setHistory(newHistory);

    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(newHistory));
    } catch (e) {
      console.warn("Storage limit reached. Pruning to save space...");

      // Attempt to prune to 5 most recent items
      let pruned = [...newHistory].slice(0, MIN_HISTORY_COUNT);

      try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(pruned));
        setHistory(pruned);
      } catch (innerError) {
        // If 5 items still don't fit (due to large base64 images), 
        // we strip images from older history items to save the text
        console.warn("Even 5 items with images too large. Stripping images from older entries.");
        const compactPruned = pruned.map((item, idx) => {
          if (idx === 0) return item; // Keep images for the very latest one
          return {
            ...item,
            slides: item.slides.map(s => ({ ...s, imageUrl: undefined }))
          };
        });

        try {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(compactPruned));
          setHistory(compactPruned);
        } catch (finalError) {
          console.error("Critical storage failure. History cannot be saved.");
        }
      }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brainDump.trim()) return;

    setStatus(AppStatus.PROCESSING);
    setError(null);

    try {
      const presentationData = await processBrainDump(brainDump);
      setResult(presentationData);

      setStatus(AppStatus.GENERATING_IMAGES);
      setImageProgress({ current: 0, total: presentationData.slides.length });

      const slidesWithImages: Slide[] = [];
      for (let i = 0; i < presentationData.slides.length; i++) {
        const slide = presentationData.slides[i];
        setImageProgress(prev => ({ ...prev, current: i + 1 }));
        const imageUrl = await generateSlideImage(slide.title, slide.visualContent);
        slidesWithImages.push({ ...slide, imageUrl });
      }

      const finalResult = { ...presentationData, slides: slidesWithImages };
      setResult(finalResult);

      // Save to history (at the beginning)
      const newHistory = [finalResult, ...history];
      saveHistory(newHistory);

      setStatus(AppStatus.COMPLETED);
      setTimeout(() => {
        document.getElementById('results')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err: any) {
      setError(err.message || 'Something went wrong. Take a breath, we can try again.');
      setStatus(AppStatus.ERROR);
    }
  };

  const handlePptxExport = async (p: Presentation) => {
    setIsExporting(true);
    try {
      await exportToPptx(p);
    } catch (err) {
      console.error("Export failed", err);
      alert("Export failed. You can still copy-paste manually!");
    } finally {
      setIsExporting(false);
    }
  };

  const handleCopyText = (p: Presentation) => {
    const text = p.slides.map((s, i) => 
      `SLIDE ${i+1}: ${s.title}\n` +
      `POINTS:\n${s.bullets.map(b => `- ${b}`).join('\n')}\n` +
      `NOTES: ${s.speakerNotes}\n` +
      `VISUAL: ${s.visualContent}\n` +
      `-------------------`
    ).join('\n\n');

    navigator.clipboard.writeText(text).then(() => {
      alert("Presentation text copied!");
    });
  };

  const handleDeleteHistory = (id: string) => {
    if (confirm("Are you sure you want to delete this session?")) {
      const newHistory = history.filter(h => h.id !== id);
      saveHistory(newHistory);
    }
  };

  const handleSelectFromHistory = (p: Presentation) => {
    setResult(p);
    setStatus(AppStatus.COMPLETED);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const reset = () => {
    setStatus(AppStatus.IDLE);
    setResult(null);
    setBrainDump('');
    setError(null);
    setShowVoiceRecorder(false);
    setImageProgress({ current: 0, total: 0 });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const toggleHistory = () => {
    if (status === AppStatus.HISTORY) {
      setStatus(AppStatus.IDLE);
    } else {
      setStatus(AppStatus.HISTORY);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20 selection:bg-indigo-100 selection:text-indigo-700">
      {/* Header */}
      <header className="py-10 px-6 max-w-5xl mx-auto flex justify-between items-center">
        <div 
          className="flex items-center gap-2 group cursor-pointer" 
          onClick={reset}
        >
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-2xl group-hover:rotate-6 transition-transform">
            🧠
          </div>
          <h1 className="text-2xl font-bold font-heading tracking-tight text-slate-800">
            Brain-Dump <span className="text-indigo-600">→</span> Slides
          </h1>
        </div>

        <div className="flex items-center gap-3">
          <Button 
            variant="ghost" 
            onClick={toggleHistory}
            className={`relative ${status === AppStatus.HISTORY ? 'bg-indigo-50 border-indigo-200 text-indigo-600' : ''}`}
          >
            History
            {history.length > 0 && (
              <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-indigo-600 text-[10px] font-bold text-white border-2 border-white">
                {history.length}
              </span>
            )}
          </Button>
          {(status === AppStatus.COMPLETED || status === AppStatus.HISTORY) && (
            <Button variant="ghost" onClick={reset}>
              New Dump
            </Button>
          )}
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6">
        {/* History View */}
        {status === AppStatus.HISTORY && (
          <HistoryView 
            history={history}
            onSelect={handleSelectFromHistory}
            onDelete={handleDeleteHistory}
            onExport={handlePptxExport}
          />
        )}

        {/* Input Section */}
        {status === AppStatus.IDLE && (
          <div className="space-y-8 animate-in fade-in duration-700">
            <div className="text-center space-y-4 max-w-2xl mx-auto">
              <h2 className="text-4xl md:text-5xl font-bold text-slate-900 leading-tight">
                Turn your brain spill into slides in <span className="text-indigo-600">60 seconds.</span>
              </h2>
              <p className="text-lg text-slate-500 leading-relaxed">
                ADHD-friendly organizing. Just paste your messy notes or talk to us directly. We'll even generate custom AI visuals for every slide.
              </p>
            </div>

            <div className="grid gap-8">
               {showVoiceRecorder ? (
                 <VoiceRecorder 
                   onTranscriptUpdate={(text) => setBrainDump(text)}
                   onFinished={() => setShowVoiceRecorder(false)}
                 />
               ) : (
                 <div className="flex justify-center">
                    <Button 
                      variant="secondary" 
                      onClick={() => setShowVoiceRecorder(true)}
                      className="bg-indigo-100 text-indigo-700 hover:bg-indigo-200 shadow-none border border-indigo-200"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                      </svg>
                      Voice Brain-Dump
                    </Button>
                 </div>
               )}

              <form onSubmit={handleSubmit} className="relative glass-panel rounded-3xl p-2 shadow-2xl border border-white">
                <textarea
                  className="w-full h-80 p-8 rounded-2xl bg-transparent focus:outline-none text-lg text-slate-700 placeholder:text-slate-400 resize-none"
                  placeholder="Type or paste your messy thoughts here..."
                  value={brainDump}
                  onChange={(e) => setBrainDump(e.target.value)}
