      } else {
        // SIDE-BY-SIDE LAYOUT
        const imgW = 5.0;
        const imgH = 2.81; 
        const imgY = (SLIDE_H - imgH) / 2;

        s.addShape(pres.ShapeType.rect, {
          x: 0, y: 0, w: 5.5, h: SLIDE_H,
          fill: { color: "F1F5F9" }
        });

        s.addImage({ 
          data: slide.imageUrl, 
          x: 0.25, 
          y: imgY, 
          w: imgW, 
          h: imgH,
          sizing: { type: 'contain', w: imgW, h: imgH }
        });

        const contentX = 5.8;
        const contentW = 3.8;

        s.addText(slide.title, {
