}

export const HistoryView: React.FC<HistoryViewProps> = ({ history, onSelect, onDelete, onExport }) => {
  const formatDate = (ts: number) => {
    return new Intl.DateTimeFormat('en-US', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    }).format(new Date(ts));
