export const exportToDocx = async (presentation: Presentation) => {
  const children = [
    new Paragraph({
      text: presentation.title,
      heading: HeadingLevel.TITLE,
      alignment: AlignmentType.CENTER,
      spacing: { after: 200 }
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [
        new TextRun({
          text: `Generated for: ${presentation.summary}`,
          italics: true,
          color: "666666"
        })
      ],
      spacing: { after: 400 }
    }),
    new Paragraph({
      text: "",
      border: { bottom: { color: "DDDDDD", space: 1, value: "single", size: 6 } },
      spacing: { after: 400 }
    })
  ];

  presentation.slides.forEach((slide, index) => {
    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: `Slide ${index + 1}: ${slide.title}`,
            bold: true,
            size: 28, // 14pt
          })
        ],
        spacing: { before: 400, after: 200 }
      })
    );

    children.push(
      new Paragraph({
        text: "Slide Content Highlights:",
        bold: true,
        italics: true,
        size: 20, // 10pt
        spacing: { after: 100 }
      })
    );

    slide.bullets.forEach(bullet => {
      children.push(
        new Paragraph({
          text: bullet,
          bullet: { level: 0 },
          spacing: { after: 100 }
        })
      );
    });

    children.push(
      new Paragraph({
        text: "Speaker Script:",
        bold: true,
        size: 20, // 10pt
        spacing: { before: 200, after: 100 },
        shading: { fill: "F8FAFC" }
      })
    );

    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: slide.speakerNotes,
            size: 24, // 12pt
          })
        ],
        spacing: { after: 400 }
      })
    );

    // Add a divider except for the last slide
    if (index < presentation.slides.length - 1) {
      children.push(
        new Paragraph({
          text: "",
          border: { bottom: { color: "EEEEEE", space: 1, value: "single", size: 6 } },
          spacing: { before: 400, after: 400 }
        })
      );
    }
  });

  const doc = new Document({
    sections: [{
      properties: { type: SectionType.CONTINUOUS },
      children
    }]
  });

  const blob = await Packer.toBlob(doc);
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `${presentation.title.replace(/\s+/g, '-')}-speaker-notes.docx`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
};

