import pptxgen from "pptxgenjs";
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, SectionType, PageBreak } from "docx";
import { Presentation } from "./types";

/**
 * Standard 16:9 slide dimensions in inches for pptxgenjs
 * Width: 10, Height: 5.625
 */
const SLIDE_W = 10;
const SLIDE_H = 5.625;

export const exportToPptx = async (presentation: Presentation) => {
  const pres = new pptxgen();

  // Set layout to 16x9
  pres.layout = 'LAYOUT_16x9';

  // 1. HIGH-IMPACT TITLE SLIDE
  const titleSlide = pres.addSlide();

  if (presentation.coverImageUrl) {
    // Background Image
    titleSlide.addImage({ 
      data: presentation.coverImageUrl, 
      x: 0, 
      y: 0, 
      w: SLIDE_W, 
      h: SLIDE_H,
      sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
    });

    // Dark overlay for text readability
    titleSlide.addShape(pres.ShapeType.rect, {
      x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
      fill: { color: "000000", transparency: 40 }
    });

    // Title centered
    titleSlide.addText(presentation.title, {
      x: 0.5,
      y: 2.2,
      w: 9,
      align: "center",
      fontSize: 54,
      color: "FFFFFF",
      bold: true,
      fontFace: "Arial",
      shadow: { type: 'outer', color: '000000', blur: 3, offset: 2, angle: 45 }
    });

  } else {
    // Fallback if no cover image
    titleSlide.background = { fill: "F8FAFC" };
    titleSlide.addShape(pres.ShapeType.rect, {
      x: 0, y: 0, w: 0.5, h: SLIDE_H, fill: { color: "4F46E5" }
    });

    titleSlide.addText(presentation.title, {
      x: 1, y: 2.3, w: 8, align: "left", fontSize: 48, color: "1E293B", bold: true, fontFace: "Arial"
    });
  }

  // 2. Content Slides
  presentation.slides.forEach((slide, index) => {
    const isLastSlide = index === presentation.slides.length - 1;
    const s = pres.addSlide();
    s.background = { fill: "FFFFFF" };

    // Apply special visual treatment for the final slide to end strong
    if (isLastSlide && slide.imageUrl) {
      // FULL BACKGROUND - Conclusion Hero Slide
      s.addImage({ 
        data: slide.imageUrl, 
        x: 0, 
        y: 0, 
        w: SLIDE_W, 
        h: SLIDE_H,
        sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
      });

      // Dark overlay for closing slide
      s.addShape(pres.ShapeType.rect, {
        x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
        fill: { color: "000000", transparency: 50 }
      });

      s.addText(slide.title, {
        x: 0.5, y: 1.8, w: 9, 
        align: "center",
        fontSize: 44, bold: true, color: "FFFFFF", fontFace: "Arial"
      });

      const wrapUpText = slide.bullets.join("\n");
      s.addText(wrapUpText, {
        x: 1, y: 2.8, w: 8, 
        align: "center",
        fontSize: 20, color: "E2E8F0", fontFace: "Arial"
      });
    } else if (slide.imageUrl) {
      if (slide.recommendedAsVisualOnly) {
        // FULL BACKGROUND - Visual Hero Slide
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0, 
          y: 0, 
          w: SLIDE_W, 
          h: SLIDE_H,
          sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
        });

        s.addShape(pres.ShapeType.rect, {
          x: 0, y: 4.4, w: SLIDE_W, h: 1.225,
          fill: { color: "000000", transparency: 50 }
        });

        s.addText(slide.title, {
          x: 0.5, y: 4.6, w: 9, h: 0.8,
          align: "left",
          fontSize: 36, bold: true, color: "FFFFFF", fontFace: "Arial"
        });
      } else {
        // SIDE-BY-SIDE LAYOUT
        const imgW = 5.0;
        const imgH = 2.81; 
        const imgY = (SLIDE_H - imgH) / 2;

        s.addShape(pres.ShapeType.rect, {
          x: 0, y: 0, w: 5.5, h: SLIDE_H,
          fill: { color: "F1F5F9" }
        });

        s.addImage({ 
          data: slide.imageUrl, 
          x: 0.25, 
          y: imgY, 
          w: imgW, 
          h: imgH,
          sizing: { type: 'contain', w: imgW, h: imgH }
        });

        const contentX = 5.8;
        const contentW = 3.8;

        s.addText(slide.title, {
          x: contentX, y: 0.6, w: contentW, 
          fontSize: 28, bold: true, color: "1E293B", fontFace: "Arial",
          margin: 0
        });

        const bulletObjects = slide.bullets.map((b, idx) => ({ 
          text: b, 
          options: { 
            bullet: { code: '2022' }, 
            indentLevel: 0, 
            color: "475569", 
            fontSize: 16,
            paraSpaceBefore: idx === 0 ? 0 : 10,
            lineSpacing: 22,
            breakLine: true 
          } 
        }));

        s.addText(bulletObjects, {
          x: contentX, y: 1.6, w: contentW, h: 3.5, 
          fontSize: 16, fontFace: "Arial", align: "left", valign: "top"
        });
      }
    } else {
      // TEXT-ONLY FALLBACK
      s.addText(slide.title, {
        x: 1, y: 1.0, w: 8, fontSize: 36, bold: true, color: "1E293B", fontFace: "Arial", align: "center"
      });

      const bulletPoints = slide.bullets.map((b, idx) => ({ 
        text: b, 
        options: { 
          bullet: true, 
          color: "475569", 
          fontSize: 20, 
          lineSpacing: 28, 
          paraSpaceBefore: idx === 0 ? 0 : 12,
          breakLine: true 
        } 
      }));

      s.addText(bulletPoints, {
        x: 1.5, y: 2.2, w: 7, h: 3, fontSize: 20, fontFace: "Arial", align: "left"
      });
    }

    s.addNotes(slide.speakerNotes);
  });

  // Save File
  await pres.writeFile({ fileName: `${presentation.title.replace(/\s+/g, '-')}-${new Date().getTime()}.pptx` });
};

export const exportToDocx = async (presentation: Presentation) => {
  const children: any[] = [
    new Paragraph({
      text: presentation.title,
      heading: HeadingLevel.TITLE,
      alignment: AlignmentType.CENTER,
      spacing: { after: 200 }
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [
        new TextRun({
          text: `Brain-Dump Speaker Script & Outline`,
          bold: true,
          color: "4F46E5",
        })
      ],
      spacing: { after: 100 }
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [
        new TextRun({
          text: presentation.summary,
          italics: true,
          color: "64748B"
        })
      ],
      spacing: { after: 400 }
    }),
    new Paragraph({
      text: "",
      border: { bottom: { color: "CBD5E1", space: 1, value: "single", size: 6 } },
      spacing: { after: 400 }
    })
  ];

  presentation.slides.forEach((slide, index) => {
    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: `Slide ${index + 1}: ${slide.title}`,
            bold: true,
            size: 32, // 16pt
            color: "1E293B"
          })
        ],
        spacing: { before: index === 0 ? 0 : 400, after: 200 }
      })
    );

    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: "Main Points:",
            bold: true,
            color: "64748B",
            size: 20, // 10pt
          })
        ],
        spacing: { after: 100 }
      })
    );

    slide.bullets.forEach(bullet => {
      children.push(
        new Paragraph({
          text: bullet,
          bullet: { level: 0 },
          spacing: { after: 80 }
        })
      );
    });

    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: "What to Say:",
            bold: true,
            color: "4F46E5",
            size: 22, // 11pt
          })
        ],
        spacing: { before: 200, after: 100 }
      })
    );

    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: slide.speakerNotes,
            size: 24, // 12pt
          })
        ],
        spacing: { after: 400 }
      })
    );

    if (index < presentation.slides.length - 1) {
      children.push(new Paragraph({ children: [new PageBreak()] }));
    }
  });

  const doc = new Document({
    sections: [{
      properties: { type: SectionType.CONTINUOUS },
      children
    }]
  });

  const blob = await Packer.toBlob(doc);
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `${presentation.title.replace(/\s+/g, '-')}-speaker-notes.docx`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
};

import React, { useEffect, useState } from 'react';
import { processBrainDump, generateSlideImage } from './geminiService';
import { exportToPptx, exportToDocx } from './exportService';
import { Button } from './components/Button';
import { SlideCard } from './components/SlideCard';
import { VoiceRecorder } from './components/VoiceRecorder';
import { HistoryView } from './components/HistoryView';
import { Presentation, AppStatus, Slide } from './types';

const STORAGE_KEY = 'brain_dump_history_v1';
const MIN_HISTORY_COUNT = 5;

const App: React.FC = () => {
  const [brainDump, setBrainDump] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [result, setResult] = useState<Presentation | null>(null);
  const [history, setHistory] = useState<Presentation[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [isDocxExporting, setIsDocxExporting] = useState(false);
  const [imageProgress, setImageProgress] = useState({ current: 0, total: 0 });

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  const saveHistory = (newHistory: Presentation[]) => {
    setHistory(newHistory);

    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(newHistory));
    } catch (e) {
      console.warn("Storage limit reached. Pruning to save space...");
      let pruned = [...newHistory].slice(0, MIN_HISTORY_COUNT);

      try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(pruned));
        setHistory(pruned);
      } catch (innerError) {
        console.warn("Even 5 items with images too large. Stripping images from older entries.");
        const compactPruned = pruned.map((item, idx) => {
          if (idx === 0) return item; 
          return {
            ...item,
            slides: item.slides.map(s => ({ ...s, imageUrl: undefined }))
          };
        });

        try {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(compactPruned));
          setHistory(compactPruned);
        } catch (finalError) {
          console.error("Critical storage failure. History cannot be saved.");
        }
      }
    }
  };

  const handleSubmit = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!brainDump.trim()) return;

    setStatus(AppStatus.PROCESSING);
    setError(null);

    try {
      const presentationData = await processBrainDump(brainDump);
      setResult(presentationData);

      setStatus(AppStatus.GENERATING_IMAGES);
      setImageProgress({ current: 0, total: presentationData.slides.length + 1 });

      setImageProgress(prev => ({ ...prev, current: 1 }));
      const coverImageUrl = await generateSlideImage(presentationData.title, "A professional, inspiring, and clean cover image for a presentation. Minimalist style, vibrant colors, abstract or thematic backgrounds.");

      const slidesWithImages: Slide[] = [];
      for (let i = 0; i < presentationData.slides.length; i++) {
        const slide = presentationData.slides[i];
        setImageProgress(prev => ({ ...prev, current: i + 2 }));
        const imageUrl = await generateSlideImage(slide.title, slide.visualContent);
        slidesWithImages.push({ ...slide, imageUrl });
      }

      const finalResult = { ...presentationData, slides: slidesWithImages, coverImageUrl };
      setResult(finalResult);

      const newHistory = [finalResult, ...history];
      saveHistory(newHistory);

      setStatus(AppStatus.COMPLETED);
      setTimeout(() => {
        document.getElementById('results')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err: any) {
      setError(err.message || 'Something went wrong. Take a breath, we can try again.');
      setStatus(AppStatus.ERROR);
    }
  };

  const handlePptxExport = async (p: Presentation) => {
    setIsExporting(true);
    try {
      await exportToPptx(p);
    } catch (err) {
      console.error("Export failed", err);
      alert("Export failed.");
    } finally {
      setIsExporting(false);
    }
  };

  const handleDocxExport = async (p: Presentation) => {
    setIsDocxExporting(true);
    try {
      await exportToDocx(p);
    } catch (err) {
      console.error("Docx export failed", err);
      alert("Word export failed. You can still view notes on screen.");
    } finally {
      setIsDocxExporting(false);
    }
  };

  const handleDeleteHistory = (id: string) => {
    if (confirm("Are you sure you want to delete this session?")) {
      const newHistory = history.filter(h => h.id !== id);
      saveHistory(newHistory);
    }
  };

  const handleSelectFromHistory = (p: Presentation) => {
    setResult(p);
    setStatus(AppStatus.COMPLETED);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const reset = () => {
    setStatus(AppStatus.IDLE);
    setResult(null);
    setBrainDump('');
    setError(null);
    setImageProgress({ current: 0, total: 0 });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const toggleHistory = () => {
    if (status === AppStatus.HISTORY) {
      setStatus(AppStatus.IDLE);
    } else {
      setStatus(AppStatus.HISTORY);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20 selection:bg-indigo-100 selection:text-indigo-700">
      <header className="py-10 px-6 max-w-5xl mx-auto flex justify-between items-center">
        <div 
          className="flex items-center gap-2 group cursor-pointer" 
          onClick={reset}
        >
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-2xl group-hover:rotate-6 transition-transform">
            🧠
          </div>
          <h1 className="text-2xl font-bold font-heading tracking-tight text-slate-800">
            Brain-Dump <span className="text-indigo-600">→</span> Slides
          </h1>
        </div>

        <div className="flex items-center gap-3">
          <Button 
            variant="ghost" 
            onClick={toggleHistory}
            className={`relative ${status === AppStatus.HISTORY ? 'bg-indigo-50 border-indigo-200 text-indigo-600' : ''}`}
          >
            History
            {history.length > 0 && (
              <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-indigo-600 text-[10px] font-bold text-white border-2 border-white">
                {history.length}
              </span>
            )}
          </Button>
          {(status === AppStatus.COMPLETED || status === AppStatus.HISTORY) && (
            <Button variant="ghost" onClick={reset}>
              New Dump
            </Button>
          )}
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6">
        {status === AppStatus.HISTORY && (
          <HistoryView 
            history={history}
            onSelect={handleSelectFromHistory}
            onDelete={handleDeleteHistory}
            onExport={handlePptxExport}
            onExportDocx={handleDocxExport}
          />
        )}

        {status === AppStatus.IDLE && (
          <div className="space-y-8 animate-in fade-in duration-700">
            <div className="text-center space-y-4 max-w-2xl mx-auto">
              <h2 className="text-4xl md:text-5xl font-bold text-slate-900 leading-tight">
                Turn your brain spill into slides in <span className="text-indigo-600">60 seconds.</span>
              </h2>
              <p className="text-lg text-slate-500 leading-relaxed">
                ADHD-friendly organizing. Just paste your messy notes or talk to us directly. We'll even generate custom AI visuals for every slide.
              </p>
            </div>

            <div className="grid gap-8">
               <VoiceRecorder 
                 onTranscriptUpdate={(text) => setBrainDump(text)}
                 onFinished={() => {}} 
               />

              <div className="relative text-center">
                 <div className="absolute inset-0 flex items-center" aria-hidden="true">
                    <div className="w-full border-t border-slate-200"></div>
                 </div>
                 <div className="relative flex justify-center">
                    <span className="bg-slate-50 px-3 text-sm font-semibold text-slate-400 uppercase tracking-widest">Or Type Below</span>
                 </div>
              </div>

              <form onSubmit={handleSubmit} className="relative glass-panel rounded-3xl p-2 shadow-2xl border border-white">
                <textarea
                  className="w-full h-64 p-8 rounded-2xl bg-transparent focus:outline-none text-lg text-slate-700 placeholder:text-slate-400 resize-none"
                  placeholder="Type or paste your messy thoughts here..."
                  value={brainDump}
                  onChange={(e) => setBrainDump(e.target.value)}
                  disabled={false}
                />
                <div className="flex justify-end p-4 bg-white/50 rounded-b-2xl border-t border-slate-100/50">
                  <Button 
                    type="submit" 
                    disabled={!brainDump.trim()} 
                    isLoading={false}
                    className="w-full md:w-auto"
                  >
                    Organize My Thoughts
                  </Button>
                </div>
              </form>
            </div>
          </div>
        )}

        {(status === AppStatus.PROCESSING || status === AppStatus.GENERATING_IMAGES) && (
          <div className="fixed inset-0 bg-white/60 backdrop-blur-sm z-50 flex flex-col items-center justify-center p-6 text-center animate-in fade-in">
            <div className="w-24 h-24 mb-8 text-indigo-600">
               <svg className="animate-spin w-full h-full" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
               </svg>
            </div>
            <h3 className="text-2xl font-bold text-slate-800 mb-2">
