import pptxgen from "pptxgenjs";
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, SectionType, PageBreak } from "docx";
import { Presentation } from "./types";

/**
 * Standard 16:9 slide dimensions in inches for pptxgenjs
 * Width: 10, Height: 5.625
 */
const SLIDE_W = 10;
const SLIDE_H = 5.625;

export const exportToPptx = async (presentation: Presentation) => {
  const pres = new pptxgen();

  // Set layout to 16x9
  pres.layout = 'LAYOUT_16x9';

  // 1. HIGH-IMPACT TITLE SLIDE
  const titleSlide = pres.addSlide();

  if (presentation.coverImageUrl) {
    // Background Image
    titleSlide.addImage({ 
      data: presentation.coverImageUrl, 
      x: 0, 
      y: 0, 
      w: SLIDE_W, 
      h: SLIDE_H,
      sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
    });

    // Dark overlay for text readability
    titleSlide.addShape(pres.ShapeType.rect, {
      x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
      fill: { color: "000000", transparency: 40 }
    });

    // Title centered
    titleSlide.addText(presentation.title, {
      x: 0.5,
      y: 2.2,
      w: 9,
      align: "center",
      fontSize: 54,
      color: "FFFFFF",
      bold: true,
      fontFace: "Arial",
      shadow: { type: 'outer', color: '000000', blur: 3, offset: 2, angle: 45 }
    });

  } else {
    // Fallback if no cover image
    titleSlide.background = { fill: "F8FAFC" };
    titleSlide.addShape(pres.ShapeType.rect, {
      x: 0, y: 0, w: 0.5, h: SLIDE_H, fill: { color: "4F46E5" }
    });

    titleSlide.addText(presentation.title, {
      x: 1, y: 2.3, w: 8, align: "left", fontSize: 48, color: "1E293B", bold: true, fontFace: "Arial"
    });
  }

  // 2. Content Slides
  presentation.slides.forEach((slide, index) => {
    const isLastSlide = index === presentation.slides.length - 1;
    const s = pres.addSlide();
    s.background = { fill: "FFFFFF" };

    // Apply special visual treatment for the final slide to end strong
    if (isLastSlide && slide.imageUrl) {
      // FULL BACKGROUND - Conclusion Hero Slide
      s.addImage({ 
        data: slide.imageUrl, 
        x: 0, 
        y: 0, 
        w: SLIDE_W, 
        h: SLIDE_H,
        sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
      });

      // Dark overlay for closing slide
      s.addShape(pres.ShapeType.rect, {
        x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
        fill: { color: "000000", transparency: 50 }
      });

      s.addText(slide.title, {
        x: 0.5, y: 1.8, w: 9, 
        align: "center",
        fontSize: 44, bold: true, color: "FFFFFF", fontFace: "Arial"
      });

      const wrapUpText = slide.bullets.join("\n");
      s.addText(wrapUpText, {
        x: 1, y: 2.8, w: 8, 
        align: "center",
        fontSize: 20, color: "E2E8F0", fontFace: "Arial"
      });
    } else if (slide.imageUrl) {
      if (slide.recommendedAsVisualOnly) {
        // FULL BACKGROUND - Visual Hero Slide
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0, 
          y: 0, 
          w: SLIDE_W, 
          h: SLIDE_H,
          sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
        });

        s.addShape(pres.ShapeType.rect, {
          x: 0, y: 4.4, w: SLIDE_W, h: 1.225,
          fill: { color: "000000", transparency: 50 }
        });

        s.addText(slide.title, {
          x: 0.5, y: 4.6, w: 9, h: 0.8,
          align: "left",
          fontSize: 36, bold: true, color: "FFFFFF", fontFace: "Arial"
        });
      } else {
        // SIDE-BY-SIDE LAYOUT
        const imgW = 5.0;
        const imgH = 2.81; 
        const imgY = (SLIDE_H - imgH) / 2;

        s.addShape(pres.ShapeType.rect, {
          x: 0, y: 0, w: 5.5, h: SLIDE_H,
          fill: { color: "F1F5F9" }
        });

        s.addImage({ 
          data: slide.imageUrl, 
          x: 0.25, 
          y: imgY, 
          w: imgW, 
          h: imgH,
          sizing: { type: 'contain', w: imgW, h: imgH }
        });

        const contentX = 5.8;
        const contentW = 3.8;

        s.addText(slide.title, {
          x: contentX, y: 0.6, w: contentW, 
          fontSize: 28, bold: true, color: "1E293B", fontFace: "Arial",
          margin: 0
        });

        const bulletObjects = slide.bullets.map((b, idx) => ({ 
          text: b, 
          options: { 
            bullet: { code: '2022' }, 
            indentLevel: 0, 
            color: "475569", 
            fontSize: 16,
            paraSpaceBefore: idx === 0 ? 0 : 10,
            lineSpacing: 22,
            breakLine: true 
          } 
        }));

        s.addText(bulletObjects, {
          x: contentX, y: 1.6, w: contentW, h: 3.5, 
          fontSize: 16, fontFace: "Arial", align: "left", valign: "top"
        });
      }
    } else {
      // TEXT-ONLY FALLBACK
      s.addText(slide.title, {
        x: 1, y: 1.0, w: 8, fontSize: 36, bold: true, color: "1E293B", fontFace: "Arial", align: "center"
      });

      const bulletPoints = slide.bullets.map((b, idx) => ({ 
        text: b, 
        options: { 
          bullet: true, 
          color: "475569", 
          fontSize: 20, 
          lineSpacing: 28, 
          paraSpaceBefore: idx === 0 ? 0 : 12,
          breakLine: true 
        } 
      }));

      s.addText(bulletPoints, {
        x: 1.5, y: 2.2, w: 7, h: 3, fontSize: 20, fontFace: "Arial", align: "left"
      });
    }

    s.addNotes(slide.speakerNotes);
  });

  // Save File
  await pres.writeFile({ fileName: `${presentation.title.replace(/\s+/g, '-')}-${new Date().getTime()}.pptx` });
};

export const exportToDocx = async (presentation: Presentation) => {
  const children: any[] = [
    new Paragraph({
      text: presentation.title,
      heading: HeadingLevel.TITLE,
      alignment: AlignmentType.CENTER,
      spacing: { after: 400 }
    }),
    new Paragraph({
      text: "",
      border: { bottom: { color: "CBD5E1", space: 1, value: "single", size: 6 } },
      spacing: { after: 400 }
    })
  ];

  presentation.slides.forEach((slide, index) => {
    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: `Slide ${index + 1}: ${slide.title}`,
            bold: true,
            size: 32, // 16pt
            color: "1E293B"
          })
        ],
        spacing: { before: index === 0 ? 0 : 400, after: 200 }
      })
    );

    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: "What to Say:",
            bold: true,
            color: "4F46E5",
            size: 22, // 11pt
          })
        ],
        spacing: { before: 100, after: 100 }
      })
    );

    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: slide.speakerNotes,
            size: 24, // 12pt
          })
        ],
        spacing: { after: 400 }
      })
    );

    if (index < presentation.slides.length - 1) {
      children.push(new Paragraph({ children: [new PageBreak()] }));
    }
  });

  const doc = new Document({
    sections: [{
      properties: { type: SectionType.CONTINUOUS },
      children
    }]
  });

  const blob = await Packer.toBlob(doc);
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `${presentation.title.replace(/\s+/g, '-')}-speaker-script.docx`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
};

import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import React, { useRef, useState } from 'react';
import { Button } from './Button';

interface VoiceRecorderProps {
  onTranscriptUpdate: (text: string) => void;
  onFinished: () => void;
}

export const VoiceRecorder: React.FC<VoiceRecorderProps> = ({ onTranscriptUpdate, onFinished }) => {
  const [isConnecting, setIsConnecting] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [interimText, setInterimText] = useState('');

  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const transcriptHistoryRef = useRef<string[]>([]);
  const currentTurnTranscriptRef = useRef('');
  const streamRef = useRef<MediaStream | null>(null);

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startSession = async () => {
    setError(null);
    setIsConnecting(true);
    setInterimText('');
    transcriptHistoryRef.current = [];
    currentTurnTranscriptRef.current = '';

    try {
      // 1. Get microphone first to avoid timeout during the permission prompt
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      if (inputCtx.state === 'suspended') {
        await inputCtx.resume();
      }
      audioContextRef.current = inputCtx;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            console.log('Live session opened');
            setIsConnecting(false);
            setIsActive(true);

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);

              // Only attempt to send if the promise has resolved to prevent flooding
              sessionPromise.then((session) => {
                try {
                  session.sendRealtimeInput({ media: pcmBlob });
                } catch (sendError) {
                  console.warn('Failed to send audio chunk', sendError);
                }
              }).catch(() => {});
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              currentTurnTranscriptRef.current += text;
              setInterimText(currentTurnTranscriptRef.current);

              const fullText = [...transcriptHistoryRef.current, currentTurnTranscriptRef.current].join(' ');
              onTranscriptUpdate(fullText);
            }

            if (message.serverContent?.turnComplete) {
              if (currentTurnTranscriptRef.current.trim()) {
                transcriptHistoryRef.current.push(currentTurnTranscriptRef.current.trim());
              }
              currentTurnTranscriptRef.current = '';
              setInterimText('');
            }
          },
          onerror: (e) => {
            console.error('Live API Error Event:', e);
            // Don't stop immediately on minor errors, but log them
          },
          onclose: (e) => {
            console.log('Live session closed', e);
            setIsActive(false);
            setIsConnecting(false);
            if (e.code && e.code !== 1000 && e.code !== 1005) {
              setError(`Connection closed unexpectedly (Error ${e.code}). Please check your API key.`);
            }
          },
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: 'You are a silent, focused listener. Your only purpose is to transcribe the user\'s brain-dump into text. Do not generate audio responses. Focus entirely on capturing their spoken words accurately.'
        },
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error('Session Start Failure:', err);
      setError(err.message || 'Microphone access denied or connection failed.');
      setIsConnecting(false);
      setIsActive(false);
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }
    if (audioContextRef.current) {
      try { audioContextRef.current.close(); } catch(e) {}
      audioContextRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsActive(false);
    setIsConnecting(false);
    onFinished();
  };

  return (
    <div className="flex flex-col items-center gap-4 p-8 bg-white rounded-[2.5rem] border border-indigo-100 shadow-xl shadow-indigo-100/50 animate-in fade-in zoom-in duration-300">
      {!isActive && !isConnecting ? (
        <div className="text-center space-y-6">
          <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white mx-auto shadow-xl shadow-indigo-200 rotate-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </div>
          <div className="space-y-2">
            <h4 className="text-xl font-bold text-slate-800 font-heading">Voice Brain-Dump</h4>
            <p className="text-slate-500 max-w-xs mx-auto leading-relaxed">
              Don't worry about order or grammar. Just talk, and we'll capture everything.
            </p>
          </div>
          <Button onClick={startSession} variant="primary" className="w-full">
            Start Recording
          </Button>
          {error && (
            <div className="flex items-center justify-center gap-2 text-rose-500 text-sm font-medium bg-rose-50 py-2 px-4 rounded-xl border border-rose-100 max-w-xs text-center">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 shrink-0" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
              {error}
            </div>
          )}
        </div>
      ) : (
        <div className="text-center space-y-8 w-full py-4">
          <div className="relative flex items-center justify-center">
             <div className="absolute w-32 h-32 bg-indigo-400 rounded-full animate-ping opacity-10"></div>
             <div className="absolute w-24 h-24 bg-indigo-500 rounded-full animate-ping opacity-20 delay-75"></div>
             <div className="relative w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-white z-10 shadow-2xl shadow-indigo-300">
                <div className="flex gap-1.5 items-end h-8">
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1s_infinite] h-4"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1.2s_infinite] h-8"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_0.8s_infinite] h-6"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1.4s_infinite] h-5"></div>
                </div>
             </div>
          </div>

          <div className="space-y-4">
            <h4 className="text-lg font-bold text-indigo-600">
              {isConnecting ? 'Waiting for Mic & AI...' : 'I\'m listening...'}
            </h4>
            <div className="min-h-[100px] max-h-40 overflow-y-auto bg-slate-50/50 rounded-2xl p-6 border border-slate-100 text-slate-700 leading-relaxed text-lg shadow-inner">
              {interimText || (isConnecting ? "" : "Go ahead, spill your thoughts...")}
              <span className="inline-block w-1.5 h-5 ml-1 bg-indigo-400 animate-pulse rounded-full align-middle"></span>
            </div>
          </div>

          <div className="flex flex-col gap-3">
            <Button onClick={stopSession} variant="primary" className="bg-slate-800 hover:bg-slate-900 shadow-slate-200">
              Stop & Process Slides
            </Button>
            <p className="text-xs text-slate-400 uppercase tracking-widest font-bold">
              Press stop when you're finished venting
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Presentation } from "./types";

const presentationSchema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: "A punchy, professional, and creative title for the entire presentation (e.g., 'Navigating the Chaos', 'Vision 2025: Clear Steps')."
    },
    summary: {
      type: Type.STRING,
      description: "A reassuring summary line like: 'You gave me X messy thoughts. I turned them into Y clear slides.'"
    },
    originalThoughtCount: {
      type: Type.INTEGER,
      description: "Approximate count of distinct points found in the input."
    },
    slideCount: {
      type: Type.INTEGER,
      description: "Total number of slides generated."
    },
    slides: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bullets: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "1-4 concise bullet points."
          },
          visualContent: {
            type: Type.STRING,
            description: "Suggestions for charts, images, diagrams, or icons."
          },
          spokenContent: {
            type: Type.STRING,
            description: "A brief summary of the core message for the presenter's awareness."
          },
          speakerNotes: {
            type: Type.STRING,
            description: "A verbatim, word-for-word script for the presenter. It should sound human, natural, and engaging, but be a complete talk-track."
          },
          recommendedAsVisualOnly: {
            type: Type.BOOLEAN,
            description: "True if this slide works better as a pure visual (e.g., a powerful image or large stat)."
          }
        },
        required: ["title", "bullets", "visualContent", "spokenContent", "speakerNotes", "recommendedAsVisualOnly"]
      }
    }
  },
  required: ["title", "summary", "originalThoughtCount", "slideCount", "slides"]
};

export async function processBrainDump(text: string): Promise<Presentation> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are a supportive, high-energy presentation coach who helps people with ADHD organize their thoughts.
    Your job is to take a "brain dump" (messy, rambling, nonlinear) and turn it into a clean, logical presentation outline.

    RULES:
    1. Cluster Ideas: Group related thoughts into logical themes.
    2. Deduplicate: Remove repeated concepts. Keep the strongest version.
    3. Logical Flow: Create a sequence that tells a clear story.
    4. Minimalist Bullets: Use 1-4 short, punchy bullets per slide.
    5. VERBATIM SCRIPT: The "speakerNotes" field MUST be written as a full, verbatim script of exactly what the speaker should say. It should be warm, professional, and flow naturally from one point to the next.
    6. Reassuring Tone: In the summary, remind them they are doing a great job.
    7. Length: Aim for 6-10 slides.
    8. MANDATORY CLOSING: The final slide MUST be a concluding "Next Steps" or "Thank You" slide that provides a satisfying wrap-up.

    Output must be strictly JSON following the provided schema.
  `;

  try {
    const result = await ai.models.generateContent({
      model,
      contents: `Here is my brain dump: \n\n ${text}`,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: presentationSchema,
        temperature: 0.7,
      },
    });

    const jsonStr = result.text.trim();
    const data = JSON.parse(jsonStr);

    return {
      ...data,
      id: crypto.randomUUID(),
      timestamp: Date.now()
    } as Presentation;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to process your brain dump. Let's try again in a moment.");
  }
}

export async function generateSlideImage(slideTitle: string, visualDescription: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const prompt = `Create a high-quality, professional presentation slide background for a slide titled "${slideTitle}". Style: clean, modern, corporate-friendly but creative. Guide: ${visualDescription}. NO TEXT or UI elements.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("No image data returned from model");
  } catch (error) {
    console.error("Image Generation Error:", error);
    return "";
  }
}

