export const exportToPptx = async (presentation: Presentation) => {
  const pres = new pptxgen();
  pres.layout = 'LAYOUT_16x9';

  const titleSlide = pres.addSlide();
  if (presentation.coverImageUrl) {
    titleSlide.addImage({ 
      data: presentation.coverImageUrl, 
      x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
      sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
    });
    titleSlide.addShape(pres.ShapeType.rect, {
      x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
      fill: { color: "000000", transparency: 40 }
    });
    titleSlide.addText(presentation.title, {
      x: 0.5, y: 2.2, w: 9,
      align: "center", fontSize: 54, color: "FFFFFF", bold: true, fontFace: "Arial",
      shadow: { type: 'outer', color: '000000', blur: 3, offset: 2, angle: 45 }
    });
  } else {
    titleSlide.background = { fill: "F8FAFC" };
    titleSlide.addText(presentation.title, {
      x: 1, y: 2.3, w: 8, align: "left", fontSize: 48, color: "1E293B", bold: true, fontFace: "Arial"
    });
  }

  presentation.slides.forEach((slide, index) => {
    const s = pres.addSlide();
    s.background = { fill: "FFFFFF" };

    if (slide.imageUrl) {
      if (slide.recommendedAsVisualOnly) {
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
          sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
        });
        s.addShape(pres.ShapeType.rect, {
          x: 0, y: 4.4, w: SLIDE_W, h: 1.225,
          fill: { color: "000000", transparency: 50 }
        });
        s.addText(slide.title, {
          x: 0.5, y: 4.6, w: 9, h: 0.8,
          align: "left", fontSize: 36, bold: true, color: "FFFFFF", fontFace: "Arial"
        });
      } else {
        const imgW = 5.0;
        const imgH = 2.81; 
        const imgY = (SLIDE_H - imgH) / 2;
        s.addShape(pres.ShapeType.rect, {
          x: 0, y: 0, w: 5.5, h: SLIDE_H, fill: { color: "F1F5F9" }
        });
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0.25, y: imgY, w: imgW, h: imgH,
          sizing: { type: 'contain', w: imgW, h: imgH }
        });
        s.addText(slide.title, {
          x: 5.8, y: 0.6, w: 3.8, fontSize: 28, bold: true, color: "1E293B", fontFace: "Arial"
        });
        const bulletObjects = slide.bullets.map((b, idx) => ({ 
          text: b, 
          options: { 
            bullet: { code: '2022' }, color: "475569", fontSize: 16,
            paraSpaceBefore: idx === 0 ? 0 : 10, lineSpacing: 22, breakLine: true 
          } 
        }));
        s.addText(bulletObjects, {
          x: 5.8, y: 1.6, w: 3.8, h: 3.5, fontSize: 16, fontFace: "Arial", align: "left", valign: "top"
        });
      }
    } else {
      s.addText(slide.title, {
        x: 1, y: 1.0, w: 8, fontSize: 36, bold: true, color: "1E293B", fontFace: "Arial", align: "center"
      });
      const bulletPoints = slide.bullets.map((b, idx) => ({ 
        text: b, options: { bullet: true, color: "475569", fontSize: 20, lineSpacing: 28, paraSpaceBefore: idx === 0 ? 0 : 12, breakLine: true } 
      }));
      s.addText(bulletPoints, {
        x: 1.5, y: 2.2, w: 7, h: 3, fontSize: 20, fontFace: "Arial", align: "left"
      });
    }
    s.addNotes(slide.speakerNotes);
  });

  await pres.writeFile({ fileName: `${presentation.title.replace(/\s+/g, '-')}-${new Date().getTime()}.pptx` });
};

