import { GoogleGenAI, Type } from "@google/genai";
import { Presentation } from "./types";

const presentationSchema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: "A punchy, professional, and creative title for the entire presentation (e.g., 'Navigating the Chaos', 'Vision 2025: Clear Steps')."
    },
    summary: {
      type: Type.STRING,
      description: "A reassuring summary line like: 'You gave me X messy thoughts. I turned them into Y clear slides.'"
    },
    originalThoughtCount: {
      type: Type.INTEGER,
      description: "Approximate count of distinct points found in the input."
    },
    slideCount: {
      type: Type.INTEGER,
      description: "Total number of slides generated."
    },
    slides: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bullets: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "1-4 concise bullet points."
          },
          visualContent: {
            type: Type.STRING,
            description: "Suggestions for charts, images, diagrams, or icons."
          },
          spokenContent: {
            type: Type.STRING,
            description: "A brief summary of the core message for the presenter's awareness."
          },
          speakerNotes: {
            type: Type.STRING,
            description: "A verbatim, word-for-word script for the presenter. It should sound human, natural, and engaging, but be a complete talk-track."
          },
          recommendedAsVisualOnly: {
            type: Type.BOOLEAN,
            description: "True if this slide works better as a pure visual (e.g., a powerful image or large stat)."
          }
        },
        required: ["title", "bullets", "visualContent", "spokenContent", "speakerNotes", "recommendedAsVisualOnly"]
      }
    }
  },
  required: ["title", "summary", "originalThoughtCount", "slideCount", "slides"]
};

export async function processBrainDump(text: string): Promise<Presentation> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are a supportive, high-energy presentation coach who helps people with ADHD organize their thoughts.
    Your job is to take a "brain dump" (messy, rambling, nonlinear) and turn it into a clean, logical presentation outline.

    RULES:
    1. Cluster Ideas: Group related thoughts into logical themes.
    2. Deduplicate: Remove repeated concepts. Keep the strongest version.
    3. Logical Flow: Create a sequence that tells a clear story.
    4. Minimalist Bullets: Use 1-4 short, punchy bullets per slide.
    5. VERBATIM SCRIPT: The "speakerNotes" field MUST be written as a full, verbatim script of exactly what the speaker should say. It should be warm, professional, and flow naturally from one point to the next.
    6. Reassuring Tone: In the summary, remind them they are doing a great job.
    7. Length: Aim for 6-10 slides.
    8. MANDATORY CLOSING: The final slide MUST be a concluding "Next Steps" or "Thank You" slide that provides a satisfying wrap-up.

    Output must be strictly JSON following the provided schema.
  `;

  try {
    const result = await ai.models.generateContent({
      model,
      contents: `Here is my brain dump: \n\n ${text}`,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: presentationSchema,
        temperature: 0.7,
      },
    });

    const jsonStr = result.text.trim();
    const data = JSON.parse(jsonStr);

    return {
      ...data,
      id: crypto.randomUUID(),
      timestamp: Date.now()
    } as Presentation;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to process your brain dump. Let's try again in a moment.");
  }
}

export async function generateSlideImage(slideTitle: string, visualDescription: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    // Enhanced prompt for cohesion and avoiding abstract/generic visuals
    const prompt = `A professional, high-quality photographic image that is part of a consistent and sophisticated visual series. 
      Subject: ${visualDescription}. 
      Style: Minimalist, cinematic lighting, modern, and authentic. 
      Avoid: Abstract patterns, generic corporate clip-art, or random colors. 
      Crucial: The image must be clean, high-resolution, and have NO TEXT, NO LABELS, and NO UI elements. 
      Context: This is a background for a presentation slide titled "${slideTitle}".`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("No image data returned from model");
  } catch (error) {
    console.error("Image Generation Error:", error);
    return "";
  }
}

import pptxgen from "pptxgenjs";
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, SectionType, PageBreak, BorderStyle } from "docx";
import { Presentation } from "./types";

const SLIDE_W = 10;
const SLIDE_H = 5.625;
const THEME_ACCENT = "4F46E5"; // Indigo 600
const THEME_BG = "F8FAFC";    // Slate 50
const TEXT_MAIN = "1E293B";   // Slate 800
const TEXT_MUTED = "475569";  // Slate 600

export const exportToPptx = async (presentation: Presentation) => {
  const pres = new pptxgen();
  pres.layout = 'LAYOUT_16x9';

  // Title Slide
  const titleSlide = pres.addSlide();
  if (presentation.coverImageUrl) {
    titleSlide.addImage({ 
      data: presentation.coverImageUrl, 
      x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
      sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
    });
    titleSlide.addShape(pres.ShapeType.rect, {
      x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
      fill: { color: "000000", transparency: 50 }
    });
    titleSlide.addText(presentation.title, {
      x: 0.5, y: 2.2, w: 9,
      align: "center", fontSize: 54, color: "FFFFFF", bold: true, fontFace: "Arial",
      shadow: { type: 'outer', color: '000000', blur: 3, offset: 2, angle: 45 }
    });
  } else {
    titleSlide.background = { fill: THEME_BG };
    titleSlide.addShape(pres.ShapeType.rect, {
      x: 0, y: 0, w: 0.4, h: SLIDE_H, fill: { color: THEME_ACCENT }
    });
    titleSlide.addText(presentation.title, {
      x: 1, y: 2.3, w: 8, align: "left", fontSize: 48, color: TEXT_MAIN, bold: true, fontFace: "Arial"
    });
  }

  presentation.slides.forEach((slide, index) => {
    const s = pres.addSlide();
    s.background = { fill: THEME_BG };

    // Subtle left accent bar (Cohesion)
    s.addShape(pres.ShapeType.rect, {
      x: 0, y: 0, w: 0.15, h: SLIDE_H, fill: { color: THEME_ACCENT }
    });

    if (slide.imageUrl) {
      if (slide.recommendedAsVisualOnly) {
        // Visual Hero: Full bleed image, NO TEXT as requested
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
          sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
        });
        // No title or text added here to avoid covering wording in the image
      } else {
        // Half Image / Half Text Layout
        const imgW = 4.6;
        const imgH = 3.8; 
        const imgY = 0.9;

        s.addShape(pres.ShapeType.rect, {
          x: 0.4, y: 0.4, w: 9.2, h: 4.8, fill: { color: "FFFFFF" }
        });

        s.addImage({ 
          data: slide.imageUrl, 
          x: 0.6, y: imgY, w: imgW, h: imgH,
          sizing: { type: 'cover', w: imgW, h: imgH }
        });

        s.addText(slide.title, {
          x: 5.4, y: 0.8, w: 4.2, fontSize: 26, bold: true, color: TEXT_MAIN, fontFace: "Arial"
        });

        const bulletObjects = slide.bullets.map((b, idx) => ({ 
          text: b, 
          options: { 
            bullet: { code: '2022' }, color: TEXT_MUTED, fontSize: 16,
            paraSpaceBefore: idx === 0 ? 0 : 12, lineSpacing: 22, breakLine: true 
          } 
        }));

        s.addText(bulletObjects, {
          x: 5.4, y: 1.8, w: 4.0, h: 3.2, fontSize: 16, fontFace: "Arial", align: "left", valign: "top"
        });
      }
    } else {
      // Standard Text Layout
      s.addText(slide.title, {
        x: 1, y: 1.3, w: 8, fontSize: 34, bold: true, color: TEXT_MAIN, fontFace: "Arial", align: "center"
      });

      const bulletPoints = slide.bullets.map((b, idx) => ({ 
        text: b, options: { 
          bullet: true, 
          color: TEXT_MUTED, 
          fontSize: 20, 
          lineSpacing: 28, 
          paraSpaceBefore: idx === 0 ? 0 : 16, 
          breakLine: true 
        } 
      }));

      s.addText(bulletPoints, {
        x: 1.5, y: 2.6, w: 7, h: 2.5, fontSize: 20, fontFace: "Arial", align: "left", valign: "top"
      });
    }
    s.addNotes(slide.speakerNotes);
  });

  await pres.writeFile({ fileName: `${presentation.title.replace(/\s+/g, '-')}-${new Date().getTime()}.pptx` });
};

export const exportToDocx = async (presentation: Presentation) => {
  const children: any[] = [
    new Paragraph({
      text: "PRESENTATION SCRIPT",
      heading: HeadingLevel.HEADING_1,
      alignment: AlignmentType.CENTER,
      spacing: { after: 200 }
    }),
    new Paragraph({
      text: presentation.title,
      heading: HeadingLevel.TITLE,
      alignment: AlignmentType.CENTER,
      spacing: { after: 400 }
    }),
    new Paragraph({
      text: `Generated on ${new Date().toLocaleDateString()} • ${presentation.slideCount} Slides`,
      alignment: AlignmentType.CENTER,
      spacing: { after: 600 }
    }),
    new Paragraph({
      text: "",
      border: { bottom: { color: "CBD5E1", space: 1, style: BorderStyle.SINGLE, size: 6 } },
      spacing: { after: 800 }
    })
  ];

  presentation.slides.forEach((slide, index) => {
    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: `SLIDE ${index + 1}: ${slide.title.toUpperCase()}`,
            bold: true,
            size: 36,
            color: "1E293B"
          })
        ],
        spacing: { before: index === 0 ? 0 : 800, after: 300 }
      })
    );

    children.push(
      new Paragraph({
        children: [
          new TextRun({ text: "ON SCREEN:", bold: true, color: "94A3B8", size: 18, allCaps: true })
        ],
        spacing: { after: 100 }
      })
    );

    slide.bullets.forEach(bullet => {
      children.push(
        new Paragraph({
          text: `• ${bullet}`,
          indent: { left: 720 },
          spacing: { after: 100 }
        })
      );
    });

    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: "YOUR SCRIPT:",
            bold: true,
            color: "4F46E5",
            size: 20,
            allCaps: true
          })
        ],
        spacing: { before: 400, after: 200 }
      })
    );

    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: slide.speakerNotes,
            size: 28,
          })
        ],
        spacing: { after: 600 },
        alignment: AlignmentType.LEFT
      })
    );

    if (slide.recommendedAsVisualOnly) {
       children.push(
        new Paragraph({
          children: [
            new TextRun({
              text: "[PRO TIP: This is a Visual Hero slide. Focus on the screen and let the image speak while you deliver this section.]",
              italics: true,
              color: "B45309",
              size: 18
            })
          ],
          spacing: { after: 400 }
        })
      );
    }

    if (index < presentation.slides.length - 1) {
      children.push(new Paragraph({ children: [new PageBreak()] }));
    }
  });

  const doc = new Document({
    sections: [{
      properties: { type: SectionType.CONTINUOUS },
      children
    }]
  });

  const blob = await Packer.toBlob(doc);
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `${presentation.title.replace(/\s+/g, '-')}-verbatim-script.docx`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
};

