import { GoogleGenAI, Type } from "@google/genai";
import { Presentation } from "./types";

const presentationSchema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: "A punchy title for the presentation."
    },
    summary: {
      type: Type.STRING,
      description: "A reassuring summary line for the user."
    },
    visualTheme: {
      type: Type.STRING,
      description: "Define the artistic medium and style for the WHOLE deck based on the input (e.g., 'Bob's Burgers 2D animation', 'Cyberpunk photography', 'Minimalist 3D Pixar-style', 'Oil painting')."
    },
    originalThoughtCount: {
      type: Type.INTEGER,
    },
    slideCount: {
      type: Type.INTEGER,
    },
    slides: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bullets: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          visualContent: {
            type: Type.STRING,
            description: "Visual description for THIS slide's specific content."
          },
          spokenContent: {
            type: Type.STRING,
          },
          speakerNotes: {
            type: Type.STRING,
            description: "Verbatim word-for-word script."
          },
          recommendedAsVisualOnly: {
            type: Type.BOOLEAN,
          }
        },
        required: ["title", "bullets", "visualContent", "spokenContent", "speakerNotes", "recommendedAsVisualOnly"]
      }
    }
  },
  required: ["title", "summary", "visualTheme", "originalThoughtCount", "slideCount", "slides"]
};

export async function processBrainDump(text: string): Promise<Presentation> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are an ADHD-friendly presentation coach. Turn the user's brain dump into a clean, logical 6-10 slide presentation.
    Identify a 'visualTheme' based on their interests or the subject matter (e.g. if they mention cartoons, choose that style).
    Output strictly valid JSON.
  `;

  try {
    const result = await ai.models.generateContent({
      model,
      contents: `Brain dump: ${text}`,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: presentationSchema,
        temperature: 0.7,
      },
    });

    const data = JSON.parse(result.text.trim());
    return { ...data, id: crypto.randomUUID(), timestamp: Date.now() } as Presentation;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("Failed to process thoughts.");
  }
}

export async function generateSlideImage(slideTitle: string, visualDescription: string, theme: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const prompt = `Style: ${theme}. 
      This is a series. This image MUST perfectly match the artistic style of the rest of the deck.
      Subject: ${visualDescription}.
      Title of Slide: ${slideTitle}.
      CRITICAL: NO LABELS, NO UI ELEMENTS, NO OVERLAYS. 
      Maintain high fidelity to the '${theme}' medium. 
      Ensure the composition is cinematic and professional.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig: { aspectRatio: "16:9" } }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return "";
  } catch (error) {
    return "";
  }
}

import React, { useEffect, useState } from 'react';
import { processBrainDump, generateSlideImage } from './geminiService';
import { exportToPptx, exportToDocx } from './exportService';
