import { SlideCard } from './components/SlideCard';
import { VoiceRecorder } from './components/VoiceRecorder';
import { HistoryView } from './components/HistoryView';
import { Presentation, AppStatus, Slide } from './types';

const STORAGE_KEY = 'brain_dump_history_v1';
const MIN_HISTORY_COUNT = 5;

const App: React.FC = () => {
  const [brainDump, setBrainDump] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [result, setResult] = useState<Presentation | null>(null);
  const [history, setHistory] = useState<Presentation[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [isDocxExporting, setIsDocxExporting] = useState(false);
  const [imageProgress, setImageProgress] = useState({ current: 0, total: 0 });

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  const saveHistory = (newHistory: Presentation[]) => {
    setHistory(newHistory);
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(newHistory));
    } catch (e) {
      const pruned = [...newHistory].slice(0, MIN_HISTORY_COUNT);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(pruned));
    }
  };

  const handleSubmit = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!brainDump.trim()) return;

    setStatus(AppStatus.PROCESSING);
    setError(null);

    try {
      const presentationData = await processBrainDump(brainDump);
      setResult(presentationData);

      setStatus(AppStatus.GENERATING_IMAGES);
      setImageProgress({ current: 0, total: presentationData.slides.length + 1 });

      // Use the locked-in theme for all images
      const theme = presentationData.visualTheme;

      setImageProgress(prev => ({ ...prev, current: 1 }));
      const coverImageUrl = await generateSlideImage(presentationData.title, "Full-screen cover art representing the theme", theme);

      const slidesWithImages: Slide[] = [];
      for (let i = 0; i < presentationData.slides.length; i++) {
        const slide = presentationData.slides[i];
        setImageProgress(prev => ({ ...prev, current: i + 2 }));
        const imageUrl = await generateSlideImage(slide.title, slide.visualContent, theme);
        slidesWithImages.push({ ...slide, imageUrl });
      }

      const finalResult = { ...presentationData, slides: slidesWithImages, coverImageUrl };
      setResult(finalResult);
      saveHistory([finalResult, ...history]);

      setStatus(AppStatus.COMPLETED);
      setTimeout(() => {
        document.getElementById('results')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err: any) {
      setError(err.message || 'Something went wrong.');
      setStatus(AppStatus.ERROR);
    }
  };

  const handlePptxExport = async (p: Presentation) => {
    setIsExporting(true);
    try {
      await exportToPptx(p);
    } finally {
      setIsExporting(false);
    }
  };

  const handleDocxExport = async (p: Presentation) => {
    setIsDocxExporting(true);
    try {
      await exportToDocx(p);
    } finally {
      setIsDocxExporting(false);
    }
  };

  const reset = () => {
    setStatus(AppStatus.IDLE);
    setResult(null);
    setBrainDump('');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20 selection:bg-indigo-100 selection:text-indigo-700">
      <header className="py-10 px-6 max-w-5xl mx-auto flex justify-between items-center">
        <div className="flex items-center gap-2 group cursor-pointer" onClick={reset}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-2xl group-hover:rotate-6 transition-transform">🧠</div>
          <h1 className="text-2xl font-bold font-heading tracking-tight text-slate-800">
            Brain-Dump <span className="text-indigo-600">→</span> Slides
          </h1>
        </div>
        <div className="flex items-center gap-3">
          <Button variant="ghost" onClick={() => setStatus(status === AppStatus.HISTORY ? AppStatus.IDLE : AppStatus.HISTORY)} className="relative">
            History {history.length > 0 && <span className="ml-1 opacity-50">({history.length})</span>}
          </Button>
          {(status === AppStatus.COMPLETED) && <Button variant="ghost" onClick={reset}>New Dump</Button>}
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6">
        {status === AppStatus.HISTORY && (
          <HistoryView history={history} onSelect={(p) => {setResult(p); setStatus(AppStatus.COMPLETED);}} onDelete={(id) => saveHistory(history.filter(h => h.id !== id))} onExport={handlePptxExport} onExportDocx={handleDocxExport} />
        )}

        {status === AppStatus.IDLE && (
          <div className="space-y-8 animate-in fade-in duration-700">
            <div className="text-center space-y-4 max-w-2xl mx-auto">
              <h2 className="text-4xl md:text-5xl font-bold text-slate-900 leading-tight">Your vision, <span className="text-indigo-600">untangled.</span></h2>
              <p className="text-lg text-slate-500">Messy notes in. Clean, visual slides out.</p>
            </div>
            <div className="grid gap-8">
               <VoiceRecorder onTranscriptUpdate={setBrainDump} onFinished={() => {}} />
               <form onSubmit={handleSubmit} className="relative glass-panel rounded-3xl p-2 shadow-2xl border border-white">
                <textarea className="w-full h-64 p-8 rounded-2xl bg-transparent focus:outline-none text-lg text-slate-700 resize-none" placeholder="Type or paste your messy thoughts here..." value={brainDump} onChange={(e) => setBrainDump(e.target.value)} />
                <div className="flex justify-end p-4 bg-white/50 rounded-b-2xl border-t border-slate-100/50">
                  <Button type="submit" disabled={!brainDump.trim()} className="w-full md:w-auto">Generate Presentation</Button>
                </div>
              </form>
            </div>
          </div>
        )}

        {(status === AppStatus.PROCESSING || status === AppStatus.GENERATING_IMAGES) && (
          <div className="fixed inset-0 bg-white/60 backdrop-blur-sm z-50 flex flex-col items-center justify-center p-6 text-center animate-in fade-in">
            <div className="w-24 h-24 mb-8 text-indigo-600 animate-spin">
               <svg viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"></path></svg>
            </div>
            <h3 className="text-2xl font-bold text-slate-800">
              {status === AppStatus.PROCESSING ? 'Structuring the chaos...' : 'Applying the visual theme...'}
            </h3>
            <p className="text-slate-500 mt-2">
              {status === AppStatus.GENERATING_IMAGES && `Slide ${imageProgress.current} of ${imageProgress.total}`}
            </p>
          </div>
        )}

        {status === AppStatus.COMPLETED && result && (
          <div id="results" className="space-y-12 animate-in slide-in-from-bottom-8 duration-700">
            <div className="bg-white rounded-[3rem] p-10 border border-slate-200 shadow-sm">
               <div className="flex items-center gap-6">
                  <span className="text-4xl">✨</span>
                  <div>
                    <h2 className="text-2xl font-bold text-slate-800">{result.title}</h2>
                    <p className="text-slate-500 italic">{result.summary}</p>
                  </div>
               </div>
            </div>

            <div className="space-y-8">
              <div className="flex items-center justify-between">
                <h3 className="text-2xl font-bold text-slate-800 font-heading">Preview</h3>
                <Button onClick={() => handlePptxExport(result)} isLoading={isExporting} className="py-2 px-4 text-sm">Download .PPTX</Button>
              </div>
              <div className="space-y-8">
                {result.slides.map((slide, index) => (
                  <SlideCard key={index} slide={slide} index={index} />
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import pptxgen from "pptxgenjs";
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, SectionType, PageBreak, BorderStyle } from "docx";
import { Presentation } from "./types";

const SLIDE_W = 10;
const SLIDE_H = 5.625;
const THEME_ACCENT = "4F46E5";
const THEME_BG = "F8FAFC";
const TEXT_MAIN = "1E293B";
const TEXT_MUTED = "475569";

export const exportToPptx = async (presentation: Presentation) => {
  const pres = new pptxgen();
  pres.layout = 'LAYOUT_16x9';

  // Title Slide
  const titleSlide = pres.addSlide();
  if (presentation.coverImageUrl) {
    titleSlide.addImage({ 
      data: presentation.coverImageUrl, 
      x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
      sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
    });
    titleSlide.addShape(pres.ShapeType.rect, {
      x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
      fill: { color: "000000", transparency: 50 }
    });
    titleSlide.addText(presentation.title, {
      x: 0.5, y: 2.2, w: 9,
      align: "center", fontSize: 54, color: "FFFFFF", bold: true, fontFace: "Arial"
    });
  } else {
    titleSlide.background = { fill: THEME_BG };
    titleSlide.addText(presentation.title, {
      x: 1, y: 2.3, w: 8, align: "left", fontSize: 48, color: TEXT_MAIN, bold: true, fontFace: "Arial"
    });
  }

  presentation.slides.forEach((slide) => {
    const s = pres.addSlide();
    s.background = { fill: THEME_BG };

    if (slide.imageUrl) {
      if (slide.recommendedAsVisualOnly) {
        // Visual Hero: NO text added to preserve artwork wording
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
          sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
        });
      } else {
        // Half Layout
        s.addShape(pres.ShapeType.rect, { x: 0.4, y: 0.4, w: 9.2, h: 4.8, fill: { color: "FFFFFF" } });
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0.6, y: 0.9, w: 4.6, h: 3.8,
          sizing: { type: 'cover', w: 4.6, h: 3.8 }
        });
        s.addText(slide.title, { x: 5.4, y: 0.8, w: 4.2, fontSize: 26, bold: true, color: TEXT_MAIN, fontFace: "Arial" });
        const bulletObjects = slide.bullets.map((b, idx) => ({ 
          text: b, options: { bullet: true, color: TEXT_MUTED, fontSize: 16, paraSpaceBefore: idx === 0 ? 0 : 12, breakLine: true } 
        }));
        s.addText(bulletObjects, { x: 5.4, y: 1.8, w: 4.0, h: 3.2, fontSize: 16, fontFace: "Arial", align: "left", valign: "top" });
      }
    } else {
      s.addText(slide.title, { x: 1, y: 1.3, w: 8, fontSize: 34, bold: true, color: TEXT_MAIN, fontFace: "Arial", align: "center" });
      const bulletPoints = slide.bullets.map((b, idx) => ({ text: b, options: { bullet: true, color: TEXT_MUTED, fontSize: 20, paraSpaceBefore: idx === 0 ? 0 : 16, breakLine: true } }));
      s.addText(bulletPoints, { x: 1.5, y: 2.6, w: 7, h: 2.5, fontSize: 20, fontFace: "Arial", align: "left", valign: "top" });
    }
    s.addNotes(slide.speakerNotes);
  });

  await pres.writeFile({ fileName: `${presentation.title.replace(/\s+/g, '-')}.pptx` });
};

export const exportToDocx = async (p: Presentation) => {
  const children: any[] = [
    new Paragraph({ text: p.title, heading: HeadingLevel.TITLE, alignment: AlignmentType.CENTER }),
    new Paragraph({ text: `Script generated on ${new Date().toLocaleDateString()}`, alignment: AlignmentType.CENTER, spacing: { after: 400 } }),
  ];
  p.slides.forEach((slide, index) => {
    children.push(new Paragraph({ text: `SLIDE ${index + 1}: ${slide.title}`, heading: HeadingLevel.HEADING_1, spacing: { before: 400, after: 200 } }));
    children.push(new Paragraph({ children: [new TextRun({ text: "SCRIPT:", bold: true, color: "4F46E5" })], spacing: { after: 100 } }));
    children.push(new Paragraph({ text: slide.speakerNotes, spacing: { after: 400 } }));
    if (index < p.slides.length - 1) children.push(new Paragraph({ children: [new PageBreak()] }));
  });
  const doc = new Document({ sections: [{ children }] });
  const blob = await Packer.toBlob(doc);
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = `${p.title.replace(/\s+/g, '-')}-script.docx`;
  link.click();
};

