      description: "Identify the EXACT artistic medium and style for the WHOLE deck based on input (e.g., 'Bob's Burgers style 2D animation', 'Pixar-style 3D animation', 'Cyberpunk photography')."
    },
    originalThoughtCount: {
      type: Type.INTEGER,
    },
    slideCount: {
      type: Type.INTEGER,
    },
    slides: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bullets: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          visualContent: {
            type: Type.STRING,
            description: "Visual description for THIS slide. Be descriptive about characters and setting."
          },
          spokenContent: {
            type: Type.STRING,
          },
          speakerNotes: {
            type: Type.STRING,
            description: "Verbatim word-for-word script."
          },
          recommendedAsVisualOnly: {
            type: Type.BOOLEAN,
          }
        },
        required: ["title", "bullets", "visualContent", "spokenContent", "speakerNotes", "recommendedAsVisualOnly"]
      }
    }
  },
  required: ["title", "summary", "visualTheme", "originalThoughtCount", "slideCount", "slides"]
};

/**
 * Strips markdown code blocks (e.g., ```json ... ```) from a string to ensure valid JSON parsing.
 */
function cleanJsonString(str: string): string {
  return str.replace(/```json\n?|```/g, '').trim();
}

export async function processBrainDump(text: string): Promise<Presentation> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are an ADHD-friendly presentation coach. Turn the user's brain dump into a clean, logical 6-10 slide presentation.

    STYLE CONSISTENCY RULE:
    Identify a 'visualTheme' based on their interests or subject matter (e.g. if they mention cartoons like Bob's Burgers, lock that style in). 
    This theme will be used to generate EVERY image in the deck.

    Output strictly valid JSON. Do not include any text outside the JSON block.
  `;

  try {
    const result = await ai.models.generateContent({
      model,
      contents: `Brain dump: ${text}`,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: presentationSchema,
        temperature: 0.7,
      },
    });

    const cleanedText = cleanJsonString(result.text);
    const data = JSON.parse(cleanedText);
    return { ...data, id: crypto.randomUUID(), timestamp: Date.now() } as Presentation;
  } catch (error) {
    console.error("Gemini Structure Error:", error);
    throw new Error("Failed to process your thoughts. Try a slightly shorter or simpler brain dump.");
  }
}

export async function generateSlideImage(slideTitle: string, visualDescription: string, theme: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    // Force the model to stick to the theme with a "Locked Visual Theme" instruction
    const prompt = `LOCKED VISUAL THEME: ${theme}.
      Every image in this presentation must match this artistic style perfectly. No style-drift allowed.

      SUBJECT: ${visualDescription}.
      CONTEXT: Slide titled "${slideTitle}".

      RULES:
      1. STYLE: Exact line-weight, coloring, and character proportions of "${theme}".
      2. FIDELITY: If "${theme}" is a specific animated show, replicate its animation style precisely.
      3. CLEANLINESS: NO UI elements, NO labels, NO menu bars, NO buttons.
      4. QUALITY: High resolution, cinematic composition.

      Generate the image only.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig: { aspectRatio: "16:9" } }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return "";
  } catch (error) {
    console.error("Image Gen Error:", error);
    return "";
  }
}

import pptxgen from "pptxgenjs";
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, SectionType, PageBreak, BorderStyle } from "docx";
import { Presentation } from "./types";

// Standard 16:9 PowerPoint slide dimensions in inches
const SLIDE_W = 10;
const SLIDE_H = 5.625;
const THEME_ACCENT = "4F46E5";
const THEME_BG = "F8FAFC";
const TEXT_MAIN = "1E293B";
const TEXT_MUTED = "475569";

export const exportToPptx = async (presentation: Presentation) => {
  const pres = new pptxgen();
  pres.layout = 'LAYOUT_16x9';

  // Title Slide
  const titleSlide = pres.addSlide();
  if (presentation.coverImageUrl) {
    // sizing: 'cover' prevents aspect ratio distortion by intelligently filling the space
    titleSlide.addImage({ 
      data: presentation.coverImageUrl, 
      x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
      sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
    });
    titleSlide.addShape(pres.ShapeType.rect, {
      x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
      fill: { color: "000000", transparency: 50 }
    });
    titleSlide.addText(presentation.title, {
      x: 0.5, y: 2.2, w: 9,
      align: "center", fontSize: 54, color: "FFFFFF", bold: true, fontFace: "Arial"
    });
  } else {
    titleSlide.background = { fill: THEME_BG };
    titleSlide.addText(presentation.title, {
      x: 1, y: 2.3, w: 8, align: "left", fontSize: 48, color: TEXT_MAIN, bold: true, fontFace: "Arial"
    });
  }

  presentation.slides.forEach((slide) => {
    const s = pres.addSlide();
    s.background = { fill: THEME_BG };

    if (slide.imageUrl) {
      if (slide.recommendedAsVisualOnly) {
        // Visual Hero: Preserves the artwork as a full-bleed slide without overlays
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0, y: 0, w: SLIDE_W, h: SLIDE_H,
          sizing: { type: 'cover', w: SLIDE_W, h: SLIDE_H }
        });
      } else {
        // Balanced Layout: Image + Text
        s.addShape(pres.ShapeType.rect, { x: 0.4, y: 0.4, w: 9.2, h: 4.8, fill: { color: "FFFFFF" } });
        s.addImage({ 
          data: slide.imageUrl, 
          x: 0.6, y: 0.9, w: 4.6, h: 3.8,
          sizing: { type: 'cover', w: 4.6, h: 3.8 } // Aspect ratio safe
        });
        s.addText(slide.title, { x: 5.4, y: 0.8, w: 4.2, fontSize: 26, bold: true, color: TEXT_MAIN, fontFace: "Arial" });
        const bulletObjects = slide.bullets.map((b, idx) => ({ 
          text: b, options: { bullet: true, color: TEXT_MUTED, fontSize: 16, paraSpaceBefore: idx === 0 ? 0 : 12, breakLine: true } 
        }));
        s.addText(bulletObjects, { x: 5.4, y: 1.8, w: 4.0, h: 3.2, fontSize: 16, fontFace: "Arial", align: "left", valign: "top" });
      }
    } else {
      // Standard Layout
      s.addText(slide.title, { x: 1, y: 1.3, w: 8, fontSize: 34, bold: true, color: TEXT_MAIN, fontFace: "Arial", align: "center" });
      const bulletPoints = slide.bullets.map((b, idx) => ({ text: b, options: { bullet: true, color: TEXT_MUTED, fontSize: 20, paraSpaceBefore: idx === 0 ? 0 : 16, breakLine: true } }));
      s.addText(bulletPoints, { x: 1.5, y: 2.6, w: 7, h: 2.5, fontSize: 20, fontFace: "Arial", align: "left", valign: "top" });
    }
    s.addNotes(slide.speakerNotes);
  });

  await pres.writeFile({ fileName: `${presentation.title.replace(/\s+/g, '-')}.pptx` });
};

export const exportToDocx = async (p: Presentation) => {
  const children: any[] = [
    new Paragraph({ text: p.title, heading: HeadingLevel.TITLE, alignment: AlignmentType.CENTER }),
    new Paragraph({ text: `Script generated on ${new Date().toLocaleDateString()}`, alignment: AlignmentType.CENTER, spacing: { after: 400 } }),
  ];
  p.slides.forEach((slide, index) => {
    children.push(new Paragraph({ text: `SLIDE ${index + 1}: ${slide.title}`, heading: HeadingLevel.HEADING_1, spacing: { before: 400, after: 200 } }));
    children.push(new Paragraph({ children: [new TextRun({ text: "SCRIPT:", bold: true, color: "4F46E5" })], spacing: { after: 100 } }));
    children.push(new Paragraph({ text: slide.speakerNotes, spacing: { after: 400 } }));
    if (index < p.slides.length - 1) children.push(new Paragraph({ children: [new PageBreak()] }));
  });
  const doc = new Document({ sections: [{ children }] });
  const blob = await Packer.toBlob(doc);
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = `${p.title.replace(/\s+/g, '-')}-script.docx`;
  link.click();
};

import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import React, { useRef, useState, useEffect } from 'react';
import { Button } from './Button';

interface VoiceRecorderProps {
  onTranscriptUpdate: (text: string) => void;
  onFinished: () => void;
}

export const VoiceRecorder: React.FC<VoiceRecorderProps> = ({ onTranscriptUpdate, onFinished }) => {
  const [isConnecting, setIsConnecting] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [interimText, setInterimText] = useState('');

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const transcriptHistoryRef = useRef<string[]>([]);
  const currentTurnTranscriptRef = useRef('');
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    return () => {
      stopSession();
    };
  }, []);

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startSession = async () => {
    setError(null);
    setIsConnecting(true);
    setInterimText('');
    transcriptHistoryRef.current = [];
    currentTurnTranscriptRef.current = '';

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      if (inputCtx.state === 'suspended') {
        await inputCtx.resume();
      }
      audioContextRef.current = inputCtx;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            console.log('Live session ready');
            setIsConnecting(false);
            setIsActive(true);

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);

              // Only send if session is resolved; this handles backend proxy latency perfectly
              sessionPromise.then((session) => {
                if (session && session.sendRealtimeInput) {
                  try {
                    session.sendRealtimeInput({ media: pcmBlob });
                  } catch (err) {
                    // Ignore transient errors
                  }
                }
              }).catch(() => {});
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              currentTurnTranscriptRef.current += text;
              setInterimText(currentTurnTranscriptRef.current);

              const fullText = [...transcriptHistoryRef.current, currentTurnTranscriptRef.current].join(' ');
              onTranscriptUpdate(fullText);
            }

            if (message.serverContent?.turnComplete) {
              if (currentTurnTranscriptRef.current.trim()) {
                transcriptHistoryRef.current.push(currentTurnTranscriptRef.current.trim());
              }
              currentTurnTranscriptRef.current = '';
              setInterimText('');
            }
          },
          onerror: (e) => console.warn('WebSocket API Error:', e),
          onclose: (e) => {
            setIsActive(false);
            setIsConnecting(false);
            if (e.code && e.code !== 1000 && e.code !== 1005) {
              setError(`Session closed unexpectedly (Code ${e.code}).`);
            }
          },
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: 'Transcribe spoken words accurately. Do not reply with audio.'
        },
      });

      sessionPromiseRef.current = sessionPromise;
    } catch (err: any) {
      setError('Could not access microphone.');
      setIsConnecting(false);
      setIsActive(false);
    }
  };

  const stopSession = () => {
    if (sessionPromiseRef.current) {
      sessionPromiseRef.current.then(session => {
        try { session.close(); } catch(e) {}
      }).catch(() => {});
      sessionPromiseRef.current = null;
    }

    if (audioContextRef.current) {
      try { audioContextRef.current.close(); } catch(e) {}
      audioContextRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }

    setIsActive(false);
    setIsConnecting(false);
    onFinished();
  };

  return (
    <div className="flex flex-col items-center gap-4 p-8 bg-white rounded-[2.5rem] border border-indigo-100 shadow-xl shadow-indigo-100/50 animate-in fade-in zoom-in duration-300">
      {!isActive && !isConnecting ? (
        <div className="text-center space-y-6">
          <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white mx-auto shadow-xl shadow-indigo-200 rotate-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </div>
          <div className="space-y-2">
            <h4 className="text-xl font-bold text-slate-800 font-heading">Voice Brain-Dump</h4>
            <p className="text-slate-500 max-w-xs mx-auto leading-relaxed">
              Messy thoughts are welcome. Start talking when ready.
            </p>
          </div>
          <Button onClick={startSession} variant="primary" className="w-full">
            Start Listening
          </Button>
          {error && (
            <div className="text-rose-500 text-sm font-medium bg-rose-50 py-2 px-4 rounded-xl border border-rose-100 text-center">
              {error}
            </div>
          )}
        </div>
      ) : (
        <div className="text-center space-y-8 w-full py-4">
          <div className="relative flex items-center justify-center">
             <div className="relative w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-white z-10 shadow-2xl shadow-indigo-300">
                <div className="flex gap-1.5 items-end h-8">
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1s_infinite] h-4"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1.2s_infinite] h-8"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_0.8s_infinite] h-6"></div>
                   <div className="w-1.5 bg-white rounded-full animate-[bounce_1.4s_infinite] h-5"></div>
                </div>
             </div>
          </div>

          <div className="space-y-4">
            <h4 className="text-lg font-bold text-indigo-600">
              {isConnecting ? 'Initializing...' : 'Capturing your thoughts...'}
            </h4>
            <div className="min-h-[100px] max-h-40 overflow-y-auto bg-slate-50/50 rounded-2xl p-6 border border-slate-100 text-slate-700 text-lg shadow-inner scrollbar-hide">
              {interimText || (isConnecting ? "" : "Ready when you are...")}
            </div>
          </div>

          <Button onClick={stopSession} variant="primary" className="bg-slate-800 hover:bg-slate-900 shadow-slate-200">
            Finish & Generate Slides
          </Button>
        </div>
      )}
    </div>
  );
};

