  await pres.writeFile({ fileName: `${presentation.title.replace(/\s+/g, '-')}.pptx` });
};

export const exportToDocx = async (p: Presentation) => {
  const children: any[] = [
    new Paragraph({ 
      text: p.title, 
      heading: HeadingLevel.TITLE, 
      alignment: AlignmentType.CENTER,
      spacing: { after: 200 }
    }),
    new Paragraph({ 
      text: `Script generated on ${new Date().toLocaleDateString()}`, 
      alignment: AlignmentType.CENTER, 
      spacing: { after: 800 } 
    }),
  ];

  p.slides.forEach((slide, index) => {
    // Slide Header with a border to separate sections without page breaks
    children.push(new Paragraph({ 
      text: `SLIDE ${index + 1}: ${slide.title}`, 
      heading: HeadingLevel.HEADING_1, 
      spacing: { before: 400, after: 200 },
      border: {
        bottom: { color: "E2E8F0", space: 1, style: BorderStyle.SINGLE, size: 6 }
      }
    }));

    // Bold Script Label
    children.push(new Paragraph({ 
      children: [
        new TextRun({ 
          text: "SPEAKER SCRIPT:", 
          bold: true, 
          color: "4F46E5",
          size: 20
        })
      ], 
      spacing: { before: 200, after: 100 } 
    }));

    // The verbatim script
    children.push(new Paragraph({ 
      text: slide.speakerNotes, 
      spacing: { after: 600 },
      indent: { left: 400 }
    }));
  });

  // Footer note
  children.push(new Paragraph({
    text: "--- End of Presentation Script ---",
    alignment: AlignmentType.CENTER,
    spacing: { before: 800 }
  }));

  const doc = new Document({ 
    sections: [{ 
      properties: {
        type: SectionType.CONTINUOUS
      },
      children 
    }] 
  });

  const blob = await Packer.toBlob(doc);
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = `${p.title.replace(/\s+/g, '-')}-script.docx`;
  link.click();
};

import React, { useEffect, useState, useMemo } from 'react';
