          </Button>
          {(status === AppStatus.COMPLETED || status === AppStatus.ERROR) && <Button variant="ghost" onClick={reset}>New Dump</Button>}
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6">
        {status === AppStatus.HISTORY && (
          <HistoryView 
            history={history} 
            onSelect={(p) => {setResult(p); setStatus(AppStatus.COMPLETED);}} 
            onDelete={(id) => saveHistory(history.filter(h => h.id !== id))} 
            onExport={handlePptxExport} 
            onExportDocx={handleDocxExport} 
          />
        )}

        {status === AppStatus.IDLE && (
          <div className="space-y-8 animate-in fade-in duration-700">
            <div className="text-center space-y-4 max-w-2xl mx-auto">
              <h2 className="text-4xl md:text-5xl font-bold text-slate-900 leading-tight">Your vision, <span className="text-indigo-600">untangled.</span></h2>
